import type { Article } from '../../../common/types/law.types';

export const ARTICLES_CONST_LA_RIOJA: Article[] = [
  { id: 'const-la-rioja-art-1', lawId: 'const-la-rioja', number: '1', title: '', text: `El poder emana y pertenece exclusivamente al pueblo de la provincia, quien lo ejerce por medio de sus legítimos representantes y por las otras formas de participación democrática establecidas en esta constitución`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-2', lawId: 'const-la-rioja', number: '2', title: 'Forma de gobierno', text: `La provincia de La Rioja, parte integrante de la República Argentina, adopta para su gobierno la forma representativa, republicana, democrática y social, y en ejercicio de su autonomía, no reconoce más limitaciones a su poder que las expresamente delegadas en la Constitución Nacional al Gobierno Federal.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-3', lawId: 'const-la-rioja', number: '3', title: 'Principios del sistema político', text: `El Estado provincial garantiza a través de todos sus actos el logro de la democracia participativa en lo económico, político, social y cultural. La actividad de todos los órganos del poder público está sujeta a los principios republicanos, en particular a la publicidad de los actos, legalidad de las acciones de los funcionarios, periodicidad de las funciones y efectiva rendición de cuentas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-4', lawId: 'const-la-rioja', number: '4', title: 'Distribución del poder', text: `El Poder del Estado provincial está distribuido de acuerdo a lo establecido en esta constitución en Funciones conforme a las competencias que ella establece.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-5', lawId: 'const-la-rioja', number: '5', title: 'Preámbulo', text: `El preámbulo no es una mera enunciación de principios, sino fuente interpretativa y de orientación para establecer el alcance, significado y finalidad de las cláusulas de la presente Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-6', lawId: 'const-la-rioja', number: '6', title: 'Límites y división política', text: `La provincia tiene los límites que por derecho le corresponden con arreglo a la Constitución Nacional, las leyes vigentes y los tratados que se celebren. No podrán ser alterados sino por ley ratificada por consulta popular. El territorio de la provincia está dividido en dieciocho departamentos, con sus actuales límites determinados por la ley, los que no podrán ser modificados sin previa consulta popular de los departamentos involucrados.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-7', lawId: 'const-la-rioja', number: '7', title: 'Sede las autoridades', text: `Las autoridades centrales del gobierno residen en la ciudad de La Rioja, capital de la provincia, salvo que por ley sujeta a consulta popular se fije otra sede.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-8', lawId: 'const-la-rioja', number: '8', title: 'Irretroactividad de la ley', text: `Ninguna norma jurídica tendrá efecto retroactivo, ni podrá afectar los derechos adquiridos o alterar las obligaciones contractuales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-9', lawId: 'const-la-rioja', number: '9', title: 'Inconstitucionalidad', text: `Toda ley, decreto, ordenanza o disposición contraria a la Constitución Nacional o a esta Constitución debe ser declarada inconstitucional por los jueces, arequerimiento de parte o de oficio.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-10', lawId: 'const-la-rioja', number: '10', title: 'Supresión de tratamientos honoríficos', text: `Quedan suprimidos los tratamientos honoríficos a funcionarios y magistrados o cuerpos colegiadosde la provincia, cualquiera sea su investidura.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-11', lawId: 'const-la-rioja', number: '11', title: 'Sostenimiento del culto católico', text: `El gobierno de la provincia coopera a sostener el culto católico, apostólico y romano.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-12', lawId: 'const-la-rioja', number: '12', title: 'Alzamiento', text: `Los que se alzaren para cambiar esta Constitución,deponer los órganos de gobierno o impedir el libre ejercicio de sus facultades constitucionales, como así también los funcionarios políticos que en la provincia formaren partedel gobierno de facto que surgiere del alzamiento o subversión serán pasibles de lassanciones civiles, penales y políticas que determinen las leyes y esta Constitución. Losfuncionarios del régimen constitucional con responsabilidad política que omitieren laejecución de actos en defensa del mismo serán pasibles de idénticas sanciones. Los habitantes de la Provincia están obligados a organizarse en defensa del ordenconstitucional.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-13', lawId: 'const-la-rioja', number: '13', title: 'Límites de la libertad', text: `La Provincia no reconoce libertad paraatentar contra la libertad, sin perjuicio del derecho individual o colectivo de emisión delpensamiento dentro del terreno doctrinario, sometido únicamente a las prescripcionesde la ley.La provincia no reconoce organizaciones, cualesquiera sean sus fines, que sustentenprincipios opuestos a las libertades individuales y sociales reconocidas por esta Constitución o atentatorias del sistema democrático republicano en que esta se inspira.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-14', lawId: 'const-la-rioja', number: '14', title: 'Inhabilitaciones', text: `Quienes ejercieren funciones de responsabilidad política en los gobiernos de facto o pertenezcan a la dirigencia de las organizaciones referidas en el artículo anterior, quedan inhabilitados a perpetuidad para ocuparcargos públicos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-15', lawId: 'const-la-rioja', number: '15', title: 'Demandas contra el Estado', text: `El Estado provincial, las municipalidades y entidades descentralizadas, y demás personas jurídicas públicas puedenser demandadas, sin necesidad de autorización de la Función Legislativa, ysin que enel juicio deba gozar de privilegio alguno.Se declaran inembargables los fondos provenientes de coparticipación federal a la Provincia y coparticipación provincial a los municipios, como también los bienes destinadosa los servicios de asistencia social, salud y educación. Condenado al pago de alguna deuda, el Estado no podrá ser ejecutado en la forma ordinaria, tampoco se trabará embargo sobre bienes o fondos indispensables paracumplir sus fines o servicios públicos ni sobre los fondos que hubieren sido previstos enel presupuesto para tales fines o servicios. Cuando el Estado o las entidades demandadas no dieren cumplimiento a la sentencia dentro de los tres meses posteriores a que la misma quede firme, podrán trabarse embargos, pero solamente sobre los fondos previstos anualmente en el presupuesto para el pago de sentencias judiciales en firme; agotados los mismos, la partida podrá ser reforzada únicamente mediante el trámite previsto por la Ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-16', lawId: 'const-la-rioja', number: '16', title: 'Gestión internacional', text: `La provincia detenta la facultad de efectuar, en el orden internacional, gestiones, actos o convenios que fueren necesarios para la satisfacción de sus intereses, sin perjuicio de la política exterior delegada al Gobierno Federal.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-17', lawId: 'const-la-rioja', number: '17', title: 'Gestión interjurisdiccional', text: `La Provincia podrá celebrar acuerdos, efectuar gestiones o mantener relaciones a nivel bilateral o regional con otras provincias o con la Nación en el ámbito de sus intereses propios y sin afectar los poderes políticos delegados al Gobierno Federal. En particular, podrá acordar con la Nación sobre coparticipación de impuestos, compensación de los efectos negativos de la política económica nacional y participación en todo órgano que administre facultades concurrentes, regímenes concertados y empresas interjurisdiccionales o del Estado Nacional que exploten recursos en su territorio.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-18', lawId: 'const-la-rioja', number: '18', title: 'Intervención federal', text: `En caso de Intervención Federal, los actos que sus representantes ejecuten en el desempeño de sus funciones serán exclusivamente administrativos, con excepción de los que deriven del estado de necesidad. Serán válidos en la provincia sólo si hubieren sido realizados de acuerdo con esta Constitución y las leyes provinciales. La nulidad podrá ser declarada a instancia de parte. Los funcionarios y empleados designados por la Intervención quedarán en comisión el día en que termine la misma. Los sueldos, retribuciones, compensaciones, viáticos y demás adicionales del interventor federal, ministros, secretarios de Estado, subsecretarios y funcionarios no escalafonados designados por la Intervención no serán abonados por el Gobierno de la provincia.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-19', lawId: 'const-la-rioja', number: '19', title: 'Derechos humanos', text: `Todos los habitantes de la Provincia son por su naturaleza libres e independientes y tienen derecho a defender su vida, libertad, reputación, integridad moral y física y seguridad individual. Nadie puede ser privado de su libertad sino por vía de penalidad, con arreglo a una ley anterior al hecho del proceso y previa sentencia de juez competente. No podrán crearse organizaciones oficiales especiales que, so pretexto de seguridad, atenten o violen los derechos humanos. Nadie podrá ser sometido a torturas, tratos crueles, degradantes o inhumanos. Todo acto de esta naturaleza hace responsable a la autoridad que lo ordene, consienta, ejecute, instigue o encubra y el Estado reparará el daño que el hecho provoque. No excusa de esta responsabilidad la obediencia debida.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-20', lawId: 'const-la-rioja', number: '20', title: 'Acciones privadas', text: `Nadie está obligado a hacer lo que la ley no manda ni privado de lo que ella no prohíbe. Las acciones privadas de los hombres que de ningún modo ofendan al orden y a la moral pública, ni perjudiquen a un tercero, están reservadas a Dios y exentas de la autoridad de los magistrados.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-21', lawId: 'const-la-rioja', number: '21', title: 'Igualdad', text: `Todos los habitantes tienen idéntica dignidad social y son iguales ante la ley, sin distinciones ni privilegios por razones de sexo, raza, religión o cualquier otra condición socioeconómica o política. El Estado propenderá al pleno desarrollo de la persona humana y a la efectiva Participación de todos los habitantes en la organización política, económica y social de La provincia, removiendo los obstáculos de orden jurídico, económico y social que, limitando de hecho la libertad y la igualdad de los mismos, impidan tal realización.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-22', lawId: 'const-la-rioja', number: '22', title: 'Presunción de inocencia', text: `Toda persona es inocente mientras no haya sido declarada su culpabilidad por sentencia firme de juez competente, dictada previo proceso legal. La privación de la libertad durante el proceso tiene el carácter excepcional, sólo puede ordenarse en los límites de esta Constitución y siempre que no exceda el término máximo que figura en la ley. Las normas que autoricen son de interpretación restrictiva, salvo el caso de flagrancia, nadie es privado de su libertad sin orden escrita y fundada de juez competente, siempre que existan elementos de convicción suficiente de participación en hecho ilícito y sea absolutamente indispensable para asegurar la investigación y la actuación de la ley. En caso de flagrancia, se dará inmediato aviso al juez competente y se pone a su disposición el aprehendido con constancia de sus antecedentes. El Estado garantiza la asistencia letrada del imputado en las diligencias policiales y judiciales, y la asistencia de oficio cuando no se designe defensor particular.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-23', lawId: 'const-la-rioja', number: '23', title: 'In dubio pro reo', text: `Desde la iniciación del proceso penal, el o los jueces que intervinieren están obligados a aplicar el principio: "in dubio pro reo". Tampoco podrán los jueces aplicar por analogía las incriminaciones legales, ni interpretar extensivamente la ley penal en contra del sospechado. Siempre se aplicará, aún con efecto retroactivo, la ley penal más favorable al imputado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-24', lawId: 'const-la-rioja', number: '24', title: 'Detención de personas', text: `En ningún caso la aprehensión, el arresto, la detención o la prisión preventiva se cumplirá en las cárceles públicas destinadas a penados, y las personas comprendidas en tales situaciones no podrán ser enviadas a establecimientos fuera de la provincia. De esta medida se dará cuenta en forma inmediata al juez competente y se pondrá a su disposición al detenido con los antecedentes del caso dentro de las veinticuatro horas. La prisión preventiva no podrá prolongarse más allá del término fijado por la ley para la finalización del proceso, en cuyo caso el detenido recuperará de inmediato la libertad. Con la privación de la libertad de una persona se labrará un acta que será firmada por ella, si es capaz, donde constará la razón del procedimiento, el lugar donde será con ducido y el magistrado interviniente, dejándosele copia de la orden y del acta labrada, a más de darle cuenta de inmediato a un familiar del detenido o a quien este indique y al Ministerio Público a los efectos de su defensa. Queda prohibida la restricción a la libertad ambulatoria para averiguación de antecedentes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-25', lawId: 'const-la-rioja', number: '25', title: 'Custodia de presos', text: `Todo encargado de la custodia de presos debe, al recibirlos, exigir y conservar en su poder la orden de detención; caso contrario, es pasible de las sanciones previstas por la ley. La misma obligación de exigir la indicada orden bajo igual responsabilidad incumbe al ejecutor del arresto o detención.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-26', lawId: 'const-la-rioja', number: '26', title: 'Cárceles', text: `Las cárceles y demás lugares destinados al cumplimiento de las penas de privación de la libertad serán sanas, limpias, y organizadas con el fin de obtener primordialmente la reeducación y readaptación del detenido, que incluirá el trabajo productivo y remunerado. Toda medida que conduzca a mortificar física o moralmente a los detenidos hará responsable a quien la ejecute, autorice o consienta. Deberá garantizarse la privacidad de los internos, el vínculo familiar y sus necesidades psicofísicas y culturales básicas. Una ley especial dispondrá la creación, organización y funcionamiento de institutos de rehabilitación y educación de menores.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-27', lawId: 'const-la-rioja', number: '27', title: 'Habeas corpus', text: `Toda persona detenida sin orden emanada en legal forma de autoridad competente o a quien arbitrariamente se restringiere o amenazare en su libertad puede por sí o por terceros en su nombre, sin necesidad de mandato, valiéndose de cualquier medio de comunicación y a cualquier hora, promover acción de hábeas corpus ante un juez letrado inmediato, a fin de que se ordene su libertad o que se someta a juez competente, o que haga cesar inmediatamente la supresión, privación o restricción que padeciere. La acción de hábeas corpus puede instaurarse sin ninguna formalidad procesal. El juez, dentro de las veinticuatro horas, examinará el caso y hará cesar inmediatamente la restricción si esta no proviene de autoridad competente, o si no cumpliere los recaudos constitucionales o legales. Cuando un juez estuviere en conocimiento de que alguna persona se hallare arbitrariamente detenida, confinada o amenazada en su libertad por un funcionario, particular, o un grupo de estos, deberá expedir de oficio el mandamiento de hábeas corpus. El juez de hábeas corpus ejerce su potestad jurisdiccional por sobre todo otro poder o autoridad pública. Todo funcionario o empleado, sin excepción de ninguna clase, está obligado a dar inmediato cumplimiento a las órdenes que imparta el juez de hábeas corpus. La ley establecerá las sanciones que correspondan a quienes rehusaren o descuidaren ese cumplimiento.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-28', lawId: 'const-la-rioja', number: '28', title: 'Amparo', text: `Procederá la acción de amparo contra cualquier decisión, acto u omisión de autoridad o de particulares que, con manifiesta ilegalidad o arbitrariedad, pusiere en peligro actual o inminente, restringiere, limitare o amenazare el ejercicio de los derechos reconocidos en esta Constitución o en la Constitución Nacional, a fin de que el juez arbitre los medios para el inmediato restablecimiento del ejercicio del derecho afectado. Esta acción procederá siempre que no pudieren uti lizarse por razones de urgencia los medios ordinarios sin daño grave e irreparable y no procediese el recurso de hábeas corpus. Cuando una disposición legal imponga a un funcionario un deber expresamente determinado, todo aquel en cuyo interés debe ejecutarse el acto o cumplirse la abstención y sufriere perjuicio material, moral o político por falta injustificada del cumplimiento del deber, puede demandar ante el juez competente su ejecución inmediata, quien previa comprobación sumaria de la obligación legal y del derecho del reclamante, dirigirá al funcionario un mandamiento de ejecución o de prohibición según el caso.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-29', lawId: 'const-la-rioja', number: '29', title: 'Habeas Data', text: `Toda persona física o jurídica podrá interponer acción de hábeas data para garantizar su derecho de autodeterminación informativa, a cuyo fin está facultada para acceder a sus datos personales y los referidos a sus bienes, y al destino de tal información que se encuentren asentados en archivos, registros, bancos de datos u otros medios técnicos, electrónicos y ópticos, de carácter público o privado, de soporte, procesamiento y provisión de la información; y, en caso de falsedad o uso discriminatorio de tales datos, exigir la supresión, rectificación, actualización o el sometimiento a confidencialidad de los mismos. No podrá afectarse el secreto de las fuentes de información periodística.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-30', lawId: 'const-la-rioja', number: '30', title: 'Defensa en juicio', text: `Es inviolable la defensa en juicio de la persona y de los derechos en todo procedimiento judicial o administrativo. En ningún caso el defensor del imputado o querellante particulares podrán ser molestados, ni allanados sus domicilios o locales profesionales con motivo del ejercicio de su ministerio. Nadie puede ser obligado a declarar contra sí mismo, su cónyuge, ascendientes, descendientes o hermanos, consanguíneos o afines. Toda declaración del imputado es un medio de defensa y deberá ser realizada ante el juez de la causa o autoridad judicial competente según lo establezca la ley, pero carecerá de valor probatorio si la misma se celebró sin la asistencia de letrado de parte u oficial. Queda abolido el secreto del sumario para las partes y prohibida la incomunicación de los detenidos sin orden de juez competente, la que en ningún caso excederá de un día. Se asegurará a los indigentes los medios para actuar o defenderse en cualquier jurisdicción o fuero.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-31', lawId: 'const-la-rioja', number: '31', title: 'Derecho a la Privacidad', text: `Son inviolables el domicilio, los papeles y registros de datos privados, la correspondencia epistolar y las comunicaciones de cualquier índole. Sólo pueden ser allanados, intervenidos, interceptados o registrados en virtud de orden escrita de juez competente. La ley limitará el uso de la informática para preservar el honor, la intimidad personal y familiar de los habitantes y el pleno ejercicio de sus derechos. El allanamiento de domicilio en horas de la noche es excepcional, debiendo el magistrado que lo dispone fundar la decisión. Las autoridades policiales sólo proporcionarán antecedentes penales de los habitantes en los casos previstos por la ley.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-32', lawId: 'const-la-rioja', number: '32', title: 'Libertad de Prensa', text: `Todo habitante de la provincia es libre de escribir, imprimir o difundir, por cualquier medio, sus ideas. Todos los habitantes gozan del derecho del libre acceso a las fuentes públicas de información. No podrá dictarse ley ni disposición alguna que coarte, restrinja o limite la libertad de prensa; que trabe, impida o suspenda por motivo alguno el funcionamiento de imprentas, talleres tipográficos, difusoras radiales o televisas y demás medios idóneos para la emisión y propagación del pensamiento; que decomise sus maquinarias o enseres, o clausure sus locales, ni expropie sus bienes. Tampoco sus labores podrán ser suspendidas, trabadas ni interrumpidas por actos o hechos del poder público que impidan o dificulten, directa o indirectamente, la libre expresión y circulación del pensamiento o la información. Sólo se considerarán abuso a la libertad de expresión los hechos constitutivos de delitos comunes. La calificación y juzgamiento de estos hechos corresponde a la justicia ordinaria, la que deberá tratar con preferencia los juicios que versen sobre la transgresión de este artículo.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-33', lawId: 'const-la-rioja', number: '33', title: 'Libertad de Culto', text: `Es inviolable el derecho que toda persona tiene de profesar su religión y ejercer su culto, libre y públicamente, según los dictados de su conciencia y sin más limitaciones que las impuestas por la moral, las buenas costumbres y el orden público. Nadie será obligado a declarar el culto que profesa.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-34', lawId: 'const-la-rioja', number: '34', title: 'Derechos del Trabajador', text: `El trabajo, como digna actividad humana, goza de la protección del Estado Provincial, quien reconoce y declara los siguientes derechos a objeto de que todas las autoridades ajusten sus acciones a los principios informadores de los mismos: derecho a trabajar, a una retribución justa, a la capacitación, a condiciones dignas de trabajo, a la participación en las ganancias de la empresa con control de su producción, cogestión o autogestión en la dirección, a la preservación de la salud, al bienestar, a la seguridad social, a la protección de su familia, al mejoramiento económico, a la defensa de sus intereses profesionales y de aprender y enseñar. El trabajo es un deber social y todo habitante de la provincia tiene la obligación moral de realizar una actividad, función u oficio que contribuya al desarrollo espiritual, cultural y material de la comunidad según su capacidad y elección. El Estado garantiza a los sindicatos los siguientes derechos: a su reconocimiento, sin otro requisito que la inscripción en un registro especial; a concertar convenios colectivos de trabajo; al ejercicio pleno y sin trabas de la gestión de los dirigentes sindicales, la estabilidad de sus empleos y la licencia gremial. En caso de duda sobre la aplicación de normas legales o convencionales Prevalecerá la más favorable al trabajador, considerándose la norma o conjunto de normas que rija cada una de las instituciones del derecho del trabajo. Si la duda recayese en la interpretación o alcances de la ley, o en la apreciación de la prueba en los casos concretos, los jueces o encargados de aplicarla decidirán en el sentido más favorable al trabajador.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-35', lawId: 'const-la-rioja', number: '35', title: 'Protección a la Familia', text: `La familia como núcleo primario y fundamental de la sociedad será objeto de preferente atención por parte del Estado provincial, el que reconoce sus derechos en lo que respecta a su constitución, defensa y cumplimiento de sus fines. La provincia promoverá la unidad económico familiar y el bien de familia, conforme a lo que una ley especial determine. La atención y asistencia de la madre y el niño gozarán de la especial consideración del Estado.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-36', lawId: 'const-la-rioja', number: '36', title: 'Educación Familiar', text: `Como una forma de protección familiar, los establecimientos e institutos de enseñanza secundaria, superior y universitaria deberán incluir en sus planes de estudio una asignatura que se refiera a aquellos aspectos de la educación de adolescentes y jóvenes que signifique prepararlos para el matrimonio, la paternidad y la vida familiar. Protección del niño y el adolescente.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-37', lawId: 'const-la-rioja', number: '37', title: '', text: `Todo niño o adolescente tiene derecho a la protección integral por cuenta y cargo de su familia. En caso de desamparo total o parcial, moral o material, permanente o transitorio, corresponde a la provincia, como inexcusable deber social, proveer a dicha protección ya sea en forma directa o por medio de institutos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-38', lawId: 'const-la-rioja', number: '38', title: 'Protección de la ancianidad', text: `Todo anciano tiene derecho a la protección integral por cuenta y cargo de su familia. En caso de desamparo, corresponde al Estado proveer a dicha protección, ya sea en forma directa o por intermedio de los institutos o fundaciones creados para ese fin.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-39', lawId: 'const-la-rioja', number: '39', title: 'Protección del Discapacitado', text: `La provincia promoverá políticas de prevención, protección, rehabilitación e integración de los discapacitados físicos y psíquicos, como asimismo aquellas tendientes a la toma de conciencia de la sociedad respecto a los deberes de solidaridad para con ellos.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-40', lawId: 'const-la-rioja', number: '40', title: 'Derecho a la vivienda', text: `EI Estado propenderá al logro de una vivienda digna para todos los habitantes de la provincia.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-41', lawId: 'const-la-rioja', number: '41', title: 'Derecho a asociarse', text: `Todo ciudadano goza del derecho de asociarse, cualquiera sea su objetivo, siempre que no afecte la moral, el orden público o el ordenamiento legal. Las asociaciones sólo pueden ser intervenidas conforme a la ley y no serán disueltas en forma compulsiva, sino en virtud de sentencia judicial.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-42', lawId: 'const-la-rioja', number: '42', title: 'Derecho de petición', text: `Queda establecido el derecho de peticionar a las autoridades, que puede ser ejercido individual o colectivamente sin que la publicación de dichas peticiones dé lugar a la aplicación de penalidad alguna a quien la formule. La autoridad a que se haya dirigido la petición está obligada a comunicar por escrito al solicitante la resolución pertinente.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-43', lawId: 'const-la-rioja', number: '43', title: 'Derecho de Reunión', text: `Los habitantes tienen derecho a reunirse sin autorización, pacíficamente y sin armas, incluso en lugares públicos, pudiendo efectuar manifestaciones públicas en forma individual o colectiva.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-44', lawId: 'const-la-rioja', number: '44', title: 'Admisibilidad en los empleos', text: `Todos los habitantes son admisibles en los empleos públicos sin más requisitos que la idoneidad y el domicilio en la provincia. La designación se efectuará por concurso público de oposición y antecedentes que garanticen la idoneidad para el cargo conforme lo reglamente la ley.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-45', lawId: 'const-la-rioja', number: '45', title: 'Estabilidad', text: `Ningún empleado o funcionario escalafonado de la provincia podrá ser separado de su cargo mientras dure su buena conducta, aptitudes físicas o mentales. La cesantía sólo se dispondrá previo sumario que justifique la medida. La Ley fijará el régimen escalafonario y asegurará la carrera administrativa, régimen disciplinario y jubilatorio.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-46', lawId: 'const-la-rioja', number: '46', title: 'Régimen de Remuneraciones', text: `La ley establecerá un régimen de remuneraciones de magistrados, funcionarios y demás empleados de la Provincia teniendo en cuenta el principio de que a igual tarea corresponde igual remuneración. Se excluye de esta limitación los siguientes adicionales particulares: antigüedad, título y asignación familiar.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-47', lawId: 'const-la-rioja', number: '47', title: 'Régimen Previsional', text: `El Régimen Jubilatorio Provincial será único para todas las personas y asegurará la equidad y la inexistencia de privilegios que importen desigualdades que no respondan a causas objetivas y razonables. El haber deberá ser móvil, irreductible y proporcional a la remuneración del mismo cargo en actividad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-48', lawId: 'const-la-rioja', number: '48', title: 'Acumulación de empleo', text: `En ningún caso podrán acumularse en una misma persona dos o más funciones o empleos rentados, ya sea provincial, municipal o nacional, con excepción de la docencia en ejercicio, con las limitaciones que la Ley deberá establecer para este último caso. Como excepción podrá contratarse profesionales universitarios por tiempo Determinado cuando sus antecedentes técnicos y científicos así lo aconsejen para la función a desempeñar.La aceptación de un nuevo empleo hace caducar automáticamente al anterior. Cuando se trate de cargos políticos podrá retenerse el empleo sin derecho a percepción de haberes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-49', lawId: 'const-la-rioja', number: '49', title: 'Responsabilidad', text: `La provincia es solidariamente responsable con sus agentes cuando éstos causaren daños a terceros por mal desempeño de sus funciones, a menos que los actos que los motiven hubieren sido ejecutados fuera de sus atribuciones.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-50', lawId: 'const-la-rioja', number: '50', title: 'Manifestación de Bienes', text: `Los que ejercen las Funciones Legislativa, Ejecutiva y Judicial están obligados, al entrar en funciones y al cesar en las mismas, a efectuar manifestación de bienes, por sí, su cónyuge y personas que la ley determine.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-51', lawId: 'const-la-rioja', number: '51', title: 'Derecho de los usuarios y consumidores', text: `Los consumidores de bienes y los usuarios de servicios tienen derecho, en la relación de consumo, a la protección de su salud, seguridad e intereses económicos, a una información adecuada y veraz, a la libertad de elección y a condiciones de trato equitativo y digno. Las autoridades proveerán a la promoción y protección de esos derechos, a la Educación para el consumo, a la defensa de la competencia contra toda forma de distorsión de los mercados, al control de los monopolios legales y naturales, al de la calidad y eficiencia de los servicios públicos, y a la constitución de asociaciones de consumidores y de usuarios. La legislación establecerá procedimientos eficaces para la prevención y solución de conflictos y los marcos regulatorios de los servicios públicos de competencia provincial; posibilitando la participación de las asociaciones de consumidores y usuarios, como también la de representantes de los Concejos Deliberantes en los organismos de control y solución de conflictos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-52', lawId: 'const-la-rioja', number: '52', title: 'Derechos Implícitos', text: `Los principios, declaraciones, derechos y garantías enumerados en esta Constitución no serán interpretados como negación de otros derechos y garantías no enumerados, pero que nacen del principio de soberanía popular, de la forma republicana de gobierno y que corresponden al hombre en su calidad de tal o como integrante de la sociedad o de sus organizaciones en donde desarrolla su personalidad y busca el cumplimiento de los deberes de solidaridad. Tampoco se entenderá como negación de los derechos que la Constitución Nacional acuerda a los habitantes de la Nación, los cuales quedan incorporados a esta Constitución.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-53', lawId: 'const-la-rioja', number: '53', title: 'Y SALUD PUBLICA Fines de la Educación', text: `La educación es un derecho humano fundamental y un deber de la familia y del Estado. Su finalidad es el desarrollo integral, permanente y armonioso de la persona, capacitándola para vivir en una sociedad democrática y participativa, basada en la ética, la libertad y la justicia social; en el respeto a las tradiciones e instituciones del país, y en los sentimientos religiosos, morales y de solidaridad humana.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-54', lawId: 'const-la-rioja', number: '54', title: 'Caracteres de la Educación', text: `El Estado asegurará el acceso a la educación, su permanencia y la posibilidad de alcanzar los más altos grados de educación. Deberá posibilitar la igualdad de oportunidades para todas las personas, desarrollando las acciones a su alcance para este fin mediante el principio de centralización normativa y descentralización operativa de tales acciones. También procurará que el estudiante de cualquier nivel pueda insertarse en el mundo productivo del trabajo sin detener el proceso educativo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-55', lawId: 'const-la-rioja', number: '55', title: 'Sistema Educacional', text: `Para el cumplimiento de los fines establecidos en esta Constitución, la provincia organizará un régimen educacional que comprenda la enseñanza pre-primaria, primaria, secundaria, superior y universitaria, que se ajustará a las siguientes bases: 1.- La educación será gratuita y asistencial; y obligatoria hasta el ciclo básico del nivel secundario y demás niveles que en lo sucesivo se establezcan por ley. 2.- La enseñanza particular privada o no oficial, será autorizada y fiscalizada por el Estado, debiendo ajustarse a las condiciones y objetivos fijados en esta Constitución. 3.- Se promoverá la consolidación de la familia, el conocimiento de la Constitución Nacional y provincial, y de la realidad provincial, nacional y latinoamericana. 4.- Se asegurará la educación permanente y sistemática, articulando la educación asistemática.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-56', lawId: 'const-la-rioja', number: '56', title: 'Consejo de Educación', text: `La coordinación de la política educativa estará a cargo de un Consejo Técnico Educativo, en el que tendrán representación los docentes y los padres, cuya denominación y funcionamiento reglamentará la ley respectiva.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-57', lawId: 'const-la-rioja', number: '57', title: 'Universidades', text: `La enseñanza universitaria será regida por un Consejo Superior formado en cada establecimiento mediante la participación de los docentes, estudiantes, egresados y no docentes. Una ley especial reglamentará su estructura funcionamiento y procedimientos a que deberá ajustarse, asegurando la autonomía universitaria con las facultades de dictar su propio estatuto, elegir sus autoridades y nombrar su personal.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-58', lawId: 'const-la-rioja', number: '58', title: 'Cultura', text: `El Estado asegurará a todos los habitantes el derecho a acceder a la cultura y eliminará toda forma de discriminación ideológica en la creación cultural. Promoverá y protegerá las manifestaciones culturales, personales y colectivas y aquellas que afirmen el sentido nacional y latinoamericano, especialmente las que fueren de reconocido arraigo y trascendencia popular en la provincia. El acervo histórico, arqueológico, artístico y documental forma, parte del patrimonio cultural de la provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-59', lawId: 'const-la-rioja', number: '59', title: 'Derecho a la Salud', text: `El Estado asegurará la salud como derecho fundamental de la persona humana. A tal efecto, tenderá a que la atención sanitaria sea gratuita, igualitaria, integral y regional, creando los organismos técnicos que garanticen la promoción, prevención, protección, asistencia y rehabilitación de la salud física, mental y social conforme al sistema que por ley se establezca. La actividad de los trabajadores de la salud será considerada como función social, garantizándose la eficaz prestación del servicio de acuerdo a las necesidades de la comunidad. Los medicamentos serán considerados como bien social básico, debiendo Disponerse por ley las medidas que aseguren su acceso para todos los habitantes. El Estado fomentará la participación activa de la comunidad y podrá celebrar Convenios con la Nación, otras provincias, o entidades privadas u otros países destinados al cumplimiento de los fines en materia de salud. Se promoverá la creación de centros de estudios e investigación, de formación y capacitación, especialmente en lo referente a los problemas de salud que afectan a la provincia y a la región.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-60', lawId: 'const-la-rioja', number: '60', title: 'Función social de la Economía', text: `La actividad económica estará al servicio del hombre y se organizará conforme a los principios sociales de esta Constitución. El Estado garantiza la libre iniciativa privada, armonizándola con los derechos de la persona y la comunidad, debiendo regular las actividades económicas a esos efectos. A tal fin se crearán los institutos y se arbitrarán los medios necesarios con intervención de representantes del trabajo, sociedades, cooperativas, asociaciones de productores, trabajadores, empresarios e instituciones oficiales de crédito para la defensa efectiva de la producción básica, la distribución de la tierra pública, el aprovechamiento de los recursos naturales, la radicación de industrias, especialmente en el interior de la provincia y la comercialización de la producción en beneficio de los productores y consumidores.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-61', lawId: 'const-la-rioja', number: '61', title: 'Función Social del Capital', text: `El capital debe tener por principal objeto el desarrollo y progreso de la provincia y sus diversas formas de explotación no pueden contrariar los fines de beneficio común del pueblo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-62', lawId: 'const-la-rioja', number: '62', title: 'Función Social de la Propiedad', text: `La propiedad privada tiene una función social y, en consecuencia la misma queda sometida a las restricciones y obligaciones que establezca la ley con fines de bien común. La expropiación por causa de utilidad pública o interés general debe ser calificada por ley y previamente indemnizada.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-63', lawId: 'const-la-rioja', number: '63', title: 'Política Agraria', text: `La tierra es considerada factor de producción y no de renta y debe ser objeto de explotación racional. La política agraria tenderá al establecimiento de unidades de producción económica racionalizadas, teniendo en cuenta las particularidades regionales de la provincia, al perfeccionamiento de los títulos de los inmuebles rurales, a la radicación del trabajador y de capitales, a la organización de productores, la promoción del acceso a los mercados, la defensa de la actividad productiva y el crédito agrario conforme a la capacidad de trabajo del agricultor.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-64', lawId: 'const-la-rioja', number: '64', title: 'Dominio de los Recursos Naturales', text: `La provincia, en el ejercicio de la soberanía inherente al pueblo es dueña originaria de todas las sustancias minerales y fuentes naturales de energía, incluidos hidrocarburos, que existen en su territorio con excepción de los vegetales. Podrá proveer a su aprovechamiento por sí o mediante acuerdos con la Nación, otras provincias o terceros, con el fin de efectuar la exploración, explotación, industrialización, preferentemente en el departamento de origen, y comercialización de las mismas, fijando de común acuerdo las regalías o retribuciones pertinentes, en lo que tendrá participación el municipio en donde se ubique el yacimiento minero. La Nación no podrá disponer de dichos recursos sin previo consentimiento de la provincia prestado por ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-65', lawId: 'const-la-rioja', number: '65', title: 'Dominio y uso de las aguas', text: `Son de dominio público de la provincia los lagos, ríos y sus afluentes y todas las aguas públicas existentes en su jurisdicción. La ley que reglamente su uso deberá establecer que toda concesión de uso y goce de aguas del dominio público es inseparable y se atribuye como derecho inherente al predio.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-66', lawId: 'const-la-rioja', number: '66', title: 'Servicios Públicos', text: `Los servicios públicos pertenecen originariamente, según su naturaleza y características, a la provincia o a las municipalidades y podrán ser concedidos a los particulares para su explotación en la forma y modo que determine la ley, priorizándose las entidades cooperativas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-67', lawId: 'const-la-rioja', number: '67', title: 'Cooperativismo', text: `El Estado, a través de la ley, fomentará y promoverá la organización, el mantenimiento y el desarrollo de cooperativas y mutuales, mediante la asistencia técnica e integral, el correcto ejercicio de la fiscalización y un adecuado plan de educación y capacitación cooperativista y mutualista.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-68', lawId: 'const-la-rioja', number: '68', title: 'Protección del Medio Ambiente', text: `Todos los habitantes gozan del derecho a un ambiente sano y equilibrado, apto para el desarrollo humano y para que las actividades productivas satisfagan las necesidades presentes sin comprometer las de las generaciones futuras; y tienen el deber de preservarlo. Las autoridades proveerán a la protección de este derecho, a la utilización racional de los recursos naturales, a la preservación del patrimonio natural y cultural y de la diversidad biológica, como así también a la información y educación ambiental, a la población en general y en particular a los educandos en sus distintos niveles. Toda actividad económica que altere el ambiente y las obras públicas o privadas que se desarrollen en el territorio provincial deberán realizar previamente un Estudio de Impacto Ambiental. Las personas físicas o jurídicas responsables de estos Emprendimientos deberán tomar los recaudos necesarios para evitar el daño ambiental, el que generará prioritariamente la obligación de recomponer el medio ambiente como se establezca en la ley. Se prohíbe en todo el territorio provincial la instalación de repositorios nucleares. Las autoridades promoverán el ordenamiento territorial ambiental para la utilización más adecuada de los recursos provinciales como también promoverán la coordinación de todos los organismos que se relacionen con la temática ambiental, concentrando en el máximo nivel posible la fijación de las políticas de recursos naturales y medio ambiente. Las autoridades gubernamentales formarán dentro del organismo competente un Cuerpo de Protección Ambiental, para fiscalización y control de los derechos y obligaciones consagrados en el presente artículo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-69', lawId: 'const-la-rioja', number: '69', title: 'Desarrollo Integral', text: `El Estado promoverá el desarrollo integral, autónomo y armónico de las diferentes zonas de su territorio.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-70', lawId: 'const-la-rioja', number: '70', title: 'Empréstitos', text: `El Régimen Financiero de la provincia se basa en el poder impositivo de la misma. En virtud del poder fiscal originario, es privativo de la provincia la creación de impuestos y contribuciones, la determinación del hecho imponible y las modalidades de percepción, con la única limitación que surge de las facultades expresamente delegadas al Gobierno Federal en virtud de lo dispuesto por la Constitución Nacional.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-71', lawId: 'const-la-rioja', number: '71', title: 'Tesoro Provincial', text: `El Estado provee a sus gastos con los fondos del Tesoro Provincial formado por los tributos, los empréstitos y créditos aprobados por ley para urgencias de la provincia o para empresas de utilidad pública, por el producido de los servicios que preste; por la administración de los bienes de dominio público y por la disposición o administración de los del dominio privado; por las actividades económicas, financieras y demás rentas o ingresos que resulten de los poderes no delegados a la Nación; por la coparticipación que provenga de los impuestos federales recaudados por los organismos competentes; y por las reparaciones que obtenga del erario nacional por efectos negativos de las políticas nacionales sobre sus recursos tributarios o no tributarios creados por ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-72', lawId: 'const-la-rioja', number: '72', title: 'Empréstitos', text: `Podrán autorizarse empréstitos sobre el crédito general de la provincia, emisión de títulos públicos u otras operaciones de crédito por ley sancionada con el voto de los dos tercios de los miembros en funciones de la Cámara de Diputados, pero ningún compromiso de esta clase podrá contraerse sino para obras públicas. En ningún caso el servicio de la totalidad de las deudas autorizadas podrá comprometer más del veinticinco por ciento de la renta provincial, a cuyo efecto se tomará como base el cálculo de recursos menor de los tres últimos años. Los recursos provenientes de ese tipo de operaciones no podrán ser distraídos ni interinamente de su objeto, bajo la responsabilidad de la autoridad que los invierta o destine a otros objetos. La ley que provea a otros compromisos extraordinarios deberá especificar los recursos especiales en que debe hacerse el servicio de la deuda y su amortización.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-73', lawId: 'const-la-rioja', number: '73', title: 'Régimen Tributario', text: `El Régimen Tributario de la provincia se estructurará sobre la base de la función económico-social de los impuestos y contribuciones. La igualdad, proporcionalidad y progresividad constituyen la base de los impuestos, contribuciones y cargas públicas. La ley establecerá el impuesto tendiente a concretar el principio de que el mayor valor de la tierra, producido sin inversión de trabajo o de capital, debe aprovechar a la comunidad.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-74', lawId: 'const-la-rioja', number: '74', title: 'Licitaciones', text: `Toda enajenación de bienes de la provincia o municipios, compra, obras públicas y demás contratos se efectuará por el sistema de subasta y licitación pública, bajo pena de nulidad, con excepción de los casos que la ley determine.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-75', lawId: 'const-la-rioja', number: '75', title: 'Presupuesto', text: `En el presupuesto se consignarán los ingresos y egresos ordinarios y extraordinarios, aún cuando hayan sido autorizados por leyes especiales, considerándose derogadas si no se incluyeren en el presupuesto las partidas correspondientes. El presupuesto sancionado seguirá en vigencia en sus partidas ordinarias hasta la sanción de uno nuevo. Ninguna ley especial que ordene o autorice gastos y carezca de recursos especiales propios podrá ser cumplida mientras la erogación no esté incluida en el presupuesto. El Proyecto de Ley de Presupuesto, emanado de la Función Ejecutiva, deberá ser elevado a la Cámara de Diputados para su tratamiento hasta el 30 de octubre del año anterior al del presupuesto que se pretende aprobar. La Función Legislativa podrá autorizar, con los dos tercios de sus miembros presentes el endeudamiento cuyo objetivo sea el financiamiento de la deuda pública, del déficit presupuestario y del desarrollo provincial.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-76', lawId: 'const-la-rioja', number: '76', title: 'Participación Política', text: `Es derecho y deber de todo ciudadano participar en la vida política. Esta Constitución reconoce los siguientes derechos políticos: 1.- Derecho a elegir y ser elegido. 2.- Derecho a constituir e integrar asociaciones de carácter político. 3.- Derecho a peticionar a las autoridades cuando la petición esté dirigida a gestionar un interés público o medidas que beneficien a un sector o a toda la comunidad. 4.- Derecho a reuniones de carácter político y a publicar ideas políticas sin censura previa. La ley reglamentará el ejercicio de estos derechos.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-77', lawId: 'const-la-rioja', number: '77', title: 'Partidos Políticos', text: `La provincia reconoce y asegura la existencia y personería de los partidos políticos, los que expresan el pluralismo democrático y concurren a la orientación, formación y manifestación de la voluntad popular. A tal fin deberán obligadamente organizar las escuelas de formación de dirigentes. A los partidos políticos les incumbe en forma exclusiva la nominación de candidatos para cargos electivos y el Estado garantiza su libre funcionamiento dentro del territorio provincial por el sólo hecho de su constitución, sin injerencia estatal o cualquier otra en su vida interna y su actividad pública. Los partidos políticos tendrán libre acceso a los medios de difusión y comunicación social en las condiciones que la ley determine. Su organización interna responderá a principios democráticos y deberán rendir cuentas públicamente sobre el origen de sus fondos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-78', lawId: 'const-la-rioja', number: '78', title: 'Bancas Legislativas', text: `Declárase que las bancas de toda representación legislativa pertenecen a los partidos políticos que han intervenido en el acto electoral y han nominado sus candidatos. Cada partido tiene la atribución de determinar si la forma en que es ejercida su representación o mandato responde al programa y doctrina política que sirvió para la exaltación del candidato al cargo que ostenta. En caso de incumplimiento en el ejercicio de su mandato, podrá el partido iniciar acción ante el Tribunal Electoral de la provincia con el fin de cuestionar el desempeño de la representación y resuelta la inconducta, queda abierta la sustitución por el suplente respectivo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-79', lawId: 'const-la-rioja', number: '79', title: 'Cuerpo electoral', text: `La representación política tiene por base la población y con arreglo a ella se ejercerá el derecho electoral. Son electores los ciudadanos de uno u otro sexo, inscriptos en el padrón electoral de la Nación y domiciliados en la provincia. Cuando el padrón electoral de la Nación no se ajuste a los principios establecidos en esta Constitución para el ejercicio del sufragio, por ley se dispondrá la formación del padrón electoral de la provincia bajo la dirección del Tribunal Electoral.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-80', lawId: 'const-la-rioja', number: '80', title: 'Sufragio electoral', text: `El sufragio electoral es un derecho inherente a la calidad de ciudadano argentino y su ejercicio una función política que tiene el deber de desempeñar con arreglo a esta Constitución y a la ley.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-81', lawId: 'const-la-rioja', number: '81', title: 'Ley Electoral', text: `La Ley Electoral será uniforme para toda la provincia y la dividirá en tantos distritos electorales como departamentos haya. La misma ley establecerá la forma en que estarán representadas las minorías. El voto es universal, libre, igual y secreto. La igualdad real de oportunidades entre varones y mujeres para el acceso a cargos electivos y partidarios se garantizará por acciones positivas en la regulación de los partidos políticos y en el régimen electoral.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-82', lawId: 'const-la-rioja', number: '82', title: 'Tribunal Electoral', text: `En la provincia funcionará un Tribunal Electoral permanente integrado por un miembro del Tribunal Superior de Justicia que lo presidirá, un juez de cámara y un miembro del ministerio público, elegidos por sorteo que efectuará el Tribunal Superior cada cuatro años. La ley fijará sus atribuciones y responsabilidades.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-83', lawId: 'const-la-rioja', number: '83', title: 'Iniciativa popular', text: `Por la iniciativa popular, el cuerpo electoral con el porcentaje que la ley determine, que no debe ser inferior al cinco por ciento del electorado, puede presentar un proyecto de ley o de derogación de leyes en vigencia para su tratamiento por la Cámara de Diputados, incluyendo la reforma constitucional. La Cámara de Diputados está obligada a considerar el proyecto. Cuando lo rechace o lo reforme sustancialmente, la iniciativa deberá someterse a consulta popular. Si el proyecto no es tratado en el término de tres meses el mismo quedará aprobado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-84', lawId: 'const-la-rioja', number: '84', title: 'Consulta Popular', text: `Las cuestiones de gobierno y la vigencia de nuevas leyes, la reforma o derogación de normas jurídicas de significativa importancia, pueden ser sometidas a consulta popular, que podrá ser obligatoria o facultativa. Será obligatoria en los siguientes casos: 1.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-177º', lawId: 'const-la-rioja', number: '177º', title: '', text: `2.- Las leyes que autorizan empréstitos cuyos servicios sean superiores al porcentaje en que se pueden afectar los recursos ordinarios. 3.- Los actos legislativos que se considere conveniente someter a consulta antes de su vigencia. Toda propuesta que sea sometida a consulta popular obligatoria se tendrá por rechazada por el pueblo si una mayoría de más del treinta y cinco por ciento de los votos de los electores inscriptos en el Registro Electoral no la aprueba.- Revocatoria Popular`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-85', lawId: 'const-la-rioja', number: '85', title: 'Toda reforma constitucional realizada por la Cámara de Diputados de acuerdo al', text: `El cuerpo electoral tiene el derecho de decidir la destitución o separación de aquellos funcionarios electivos que no han cumplido el mandato recibido o que por el mal desempeño en sus funciones han dejado de merecer la confianza depositada en ellos por el pueblo. Para que la revocatoria popular se considere válida es necesario que el resultado electoral supere el cincuenta por ciento de los electores inscriptos en el Registro Electoral.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-86', lawId: 'const-la-rioja', number: '86', title: 'de Diputados', text: `La Función Legislativa de la provincia es ejercida por la Cámara de Diputados, integrada por representantes elegidos directamente por el pueblo, con arreglo a esta Constitución y a la ley. La Cámara de Diputados es juez de los derechos y títulos de sus miembros en cuanto a su validez. Composición. Distribución. Integración.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-87', lawId: 'const-la-rioja', number: '87', title: '', text: `La Cámara de Diputados se compone de treinta y seis miembros, elegidos directamente por el pueblo de la provincia. A tal efecto, cada departamento constituirá un distrito electoral único, Distribuyéndose las bancas de la siguiente forma: en el departamento Capital: ocho; en el departamento Chilecito: cuatro; en el departamento Arauco: tres; en el departamento Coronel Felipe Varela: tres; en el departamento Chamical: tres; en el departamento Rosario Vera Peñaloza: tres; en los departamentos Castro Barros, General Belgrano, General Lamadrid, General Ortiz de Ocampo, General Juan Facundo Quiroga, General San Martín, Famatina, Independencia, Ángel Vicente Peñaloza, Sanagasta, San Blas de Los Sauces y Vinchina: uno por cada uno de ellos. Para su reparto, se adjudicará en los departamentos que tengan una sola banca por simple mayoría de sufragios. En el resto se aplicará el sistema D' Hont, y el partido que obtenga la mayoría solo podrá adjudicarse hasta un máximo de: cinco bancas en el departamento Capital; tres bancas en el departamento Chilecito; dos bancas en el departamento Arauco; dos bancas en el departamento Coronel Felipe Varela; dos bancas en el departamento Chamical, y dos bancas en el departamento Rosario Vera Peñaloza. Las restantes bancas se adjudicarán a las minorías, a cuyo fin la totalidad de los sufragios obtenidos por ellas en cada departamento, se tendrán como total electoral sobre el cual se aplicará el cociente que corresponda en porcentual a cada minoría. Nunca podrán las minorías tener un porcentual menor al equivalente a ocho bancas, pudiendo acrecer estas últimas en caso de ser mayoría en los departamentos. Ningún candidato podrá acceder a una banca si su partido político no alcanzó un mínimo del tres por ciento de la totalidad de los votos válidamente emitidos en toda la provincia. Para los cargos electivos, los partidos políticos deberán nominar sus candidatos respetando para su validez en la conformación de sus listas, lo`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-81°', lawId: 'const-la-rioja', number: '81°', title: '', text: `Dieta`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-88', lawId: 'const-la-rioja', number: '88', title: 'establecido en el segundo párrafo del', text: `Los diputados durarán cuatro años en el ejercicio de su mandato y podrán ser reelegidos. La Cámara se renovará por mitad cada dos años. El diputado suplente que se incorpore en reemplazo del titular completará el témrino del mandato.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-89', lawId: 'const-la-rioja', number: '89', title: 'Requisitos', text: `Para ser diputado se requiere ser argentino, mayor de edad, con dos años de residencia inmediata y efectiva anterior a la elección, en el departamento que representa.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-90', lawId: 'const-la-rioja', number: '90', title: 'Orden de adjudicación', text: `Corresponde adjudicar los cargos de diputados respetando el orden de colocación de los candidatos en las listas oficializadas por el Tribunal Electoral. Los que siguen serán considerados suplentes, a los que se agregarán en tal carácter los otros suplentes que la ley establezca.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-91', lawId: 'const-la-rioja', number: '91', title: 'Duración', text: `Los diputados durarán cuatro años en el ejercicio de su mandato y podrán ser reelegidos. La Cámara se renovará por mitad cada dos años. El diputado suplente que se incorpore en reemplazo del titular completará el término del mandato.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-92', lawId: 'const-la-rioja', number: '92', title: 'Incompatibilidades', text: `No pueden ser diputados los militares en servicio activo; los que hayan sido condenados a penas de reclusión o prisión mientras subsistan los efectos jurídicos de la condena; y los deudores del fisco cuando se hubiere dictado sentencia en su contra. Es incompatible el ejercicio del cargo de diputado con: a) Cualquier cargo electivo en el gobierno federal, provincial y municipal o de otras provincias, excepto el de Convencional Constituyente nacional, provincial o municipal. b) El ejercicio de una función, comisión, o empleo público dependiente del Estado Nacional, Provincial o Municipal, sin previo consentimiento de la Cámara. En ningún caso dicho consentimiento permite el ejercicio simultáneo, ni la doble percepción del cargo de diputado con el empleo, función o comisión de que se trate. Podrá ejercer la docencia en el cargo de dedicación simple en el ámbito superior o universitario. Todo diputado en ejercicio de sus funciones que acepte cualquier empleo de los declarados incompatibles, cesa, por ese hecho, de ser miembro de la Cámara. Los agentes de la administración pública provincial o municipal que resultaren elegidos diputados quedan automáticamente con licencia sin goce de sueldo desde su asunción, por el tiempo que dure su función. Ningún diputado podrá patrocinar causas contra la Nación, Provincia o Municipios, ni defender intereses privados ante la administración. Tampoco podrá participar en empresas beneficiadas con privilegios o concesiones dadas por el Estado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-93', lawId: 'const-la-rioja', number: '93', title: 'Inmunidades', text: `Los miembros de la Cámara no pueden ser acusados, interrogados judicialmente ni molestados por las opiniones o votos que emitan en el desempeño de su mandato. Todo agravio, cualquiera sea su naturaleza y forma, dirigido contra un miembro de la Cámara, dentro o fuera de ella, por causa de sus votos u opiniones en el ejercicio de sus funciones y en razón del cumplimiento de sus deberes de legislador, es ofensa a la misma Cámara, que debe ser sancionada. Ningún diputado podrá ser arrestado desde el día de su elección hasta el de su cese, excepto el caso de ser sorprendido en flagrante ejecución de un hecho ilícito doloso que merezca pena privativa de libertad; en este caso el juez que ordene la detención dará cuenta dentro de los tres días a la Cámara, con la información sumaria del hecho.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-94', lawId: 'const-la-rioja', number: '94', title: 'Desafuero', text: `La Cámara al conocer el sumario podrá allanar el fuero del arrestado por mayoría absoluta de sus miembros, debiendo considerarse allanado de hecho si la Cámara no hubiese resuelto el caso dentro de los diez días siguientes en que se recibió el sumario. Para no hacer lugar al allanamiento se requiere mayoría absoluta de votos presentes, en cuyo caso el detenido será puesto inmediatamente en libertad. Cuando se deduzca acusación ante la justicia contra un diputado, examinado el mérito de la misma en la sesión próxima a la que se diere cuenta del hecho, la Cámara, con los dos tercios de votos de la totalidad de sus componentes, podrá suspender en sus funciones al acusado y dejarlo a disposición del Juez Competente para su juzgamiento.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-95', lawId: 'const-la-rioja', number: '95', title: 'Facultad Disciplinaria', text: `La Cámara, con dos tercios de los votos de la totalidad de sus miembros, corregirá a cualquiera de ellos por desorden de conducta en el ejercicio de sus funciones o ausentismo notorio e injustificado o lo excluirá de su seno por inhabilidad física, psíquica, moral o legal sobreviniente a su incorporación.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-96', lawId: 'const-la-rioja', number: '96', title: 'Presidencia', text: `La Presidencia de la Cámara será ejercida por el Vicegobernador, quien tendrá voto sólo en caso de empate. La Cámara nombrará anualmente de su seno y en su primera sesión ordinaria Vicepresidente Primero y Segundo, quienes procederán a desempeñar la presidencia por su orden. Cuando ejerzan la presidencia tendrán voto y decidirán en caso de empate. Los nombramientos de las autoridades de la Cámara deberán hacerse por mayoría absoluta de los presentes. Si hecho el escrutinio ningún candidato obtuviera la mayoría absoluta, deberá repetirse la votación limitándose a los dos candidatos más votados. En caso de empate decidirá el presidente.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-97', lawId: 'const-la-rioja', number: '97', title: 'Investigaciones', text: `Es facultad de la Cámara designar comisiones con fines de fiscalización o investigación en cualquier dependencia de la administración pública provincial o entidades privadas cuando estuvieren comprometidos intereses del Estado. No deberá interferir en el área de atribuciones de las otras funciones y resguardará los derechos y garantías individuales. Para practicar allanamientos debe requerir la autorización del juez competente.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-98', lawId: 'const-la-rioja', number: '98', title: 'Interpelación', text: `La Cámara, con la aprobación de un tercio de sus miembros presentes, podrá llamar a su seno a los ministros para recibir las explicaciones e informes que estime convenientes, a cuyo efecto deberá citarlos con cuarenta y ocho horas de anticipación y hacerles saber los puntos sobre los cuales han de informar. El Gobernador podrá concurrir a la Cámara cuando lo estime conveniente en Reemplazo de los ministros interpelados.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-99', lawId: 'const-la-rioja', number: '99', title: 'Reglamento Interno', text: `La Cámara dictará su reglamento, el que preverá la constitución de comisiones internas encargadas de intervenir en el estudio del material legislativo. Se integrarán respetando la proporción de la representación parlamentaria de la Cámara.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-100', lawId: 'const-la-rioja', number: '100', title: 'Facultades de las Comisiones', text: `Las Comisiones Legislativas podrán dictar resoluciones, declaraciones y efectuar pedidos de informes. La Cámara podrá disponer la remisión a las mismas de asuntos de menor trascendencia para que ellas los resuelvan.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-101', lawId: 'const-la-rioja', number: '101', title: 'Comisión Permanente', text: `La Cámara podrá designar de su seno, antes de entrar en receso, una Comisión Permanente a la que le corresponderán las siguientes funciones: seguir la actividad de administración, promover la convocatoria de la Cámara siempre que fuere necesario y preparar la apertura del nuevo período de sesiones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-102', lawId: 'const-la-rioja', number: '102', title: 'Período de Sesiones', text: `La Cámara se reunirá en sesiones ordinarias todos los años desde el primer día hábil del mes de marzo hasta el quince del mes de diciembre, pudiendo por sí prorrogarlas por el término que sea necesario. La Cámara podrá ser convocada a sesiones extraordinarias por el gobernador cuando mediaren razones de urgente interés público y por el presidente del cuerpo cuando lo solicitare la tercera parte de sus miembros. En tales casos, se tratarán únicamente los asuntos que motivaron la convocatoria.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-103', lawId: 'const-la-rioja', number: '103', title: 'Quorum', text: `La Cámara sesionará con la presencia de la mitad más uno de sus componentes. Podrá realizar sesiones en minoría al sólo efecto de acordar medidas para compeler a los inasistentes. Las sesiones serán públicas salvo que en razón de la naturaleza del asunto se resolviere lo contrario.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-104', lawId: 'const-la-rioja', number: '104', title: 'Declaraciones', text: `La Cámara podrá expresar la opinión de su mayoría por medio de resoluciones o declaraciones sin fuerza de ley sobre cualquier asunto político o administrativo atinente a los intereses generales de la Provincia o de la Nación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-105', lawId: 'const-la-rioja', number: '105', title: 'Atribuciones', text: `Corresponde a la Cámara de Diputados: Inciso 1.- Dictar todas las leyes necesarias para el ejercicio de las instituciones creadas por esta Constitución, así como las relativas a todo asunto de interés público y general de la provincia; Inciso 2.- Establecer tributos para la formación del tesoro provincial; Inciso 3.- Fijar anualmente el presupuesto de gastos y el cálculo de recursos. Podrá fijarse por un periodo mayor siempre que no exceda el término del mandato del gobernador en ejercicio y que se establezca en base a ejercicio anuales; Inciso 4.- Aprobar, rechazar u observar en el plazo de noventa días las cuentas de inversión que deberá presentar el gobernador hasta el treinta de junio de cada año respecto al ejercicio anterior; Inciso 5.- Legislar sobre el uso, distribución y enajenación de las tierras del Estado provincial, requiriendo los dos tercios de los votos de sus miembros para la cesión de tierras fiscales con el objeto de utilidad social expresamente determinada; Inciso 6.- Autorizar al gobernador a contraer empréstitos, títulos públicos y celebrar cualquier otra operación de crédito con arreglo a lo dispuesto por esta Constitución; Inciso 7.- Crear y suprimir bancos oficiales y legislar sobre el régimen bancario y crediticio; Inciso 8.- Crear y suprimir cargos o empleos no establecidos expresamente por esta Constitución, determinando sus atribuciones y responsabilidades; Inciso 9.- Declarar la utilidad pública o el interés general en los casos de expropiación por leyes generales o especiales, determinando los fondos con que debe abonarse la indemnización. Inciso 10.- Establecer o modificar las divisiones departamentales conforme a lo establecido en esta Constitución; Inciso 11.- Acordar amnistías generales; Inciso 12.- Aprobar o desechar los tratados o convenios que el gobernador acuerde con el Estado Nacional, otras provincias o municipios, entes públicos o privados nacionales o extranjeros, estados extranjeros u organismos internacionales; Inciso 13.- Recibir el juramento de ley al gobernador y vicegobernador de la provincia y considerar las renuncias que hicieren a su cargo; Inciso 14.- Conceder o denegar la licencia al gobernador y vicegobernador en ejercicio, para salir del territorio de la provincia por más de treinta días; Inciso 15.- Prestar o denegar acuerdos para los nombramientos que requieren esta formalidad, entendiéndose acordado si dentro de los treinta días de recibida la comunicación correspondiente no se hubiera expedido; Inciso 16.- Efectuar los nombramientos que correspondan conforme a esta Constitución; Inciso 17.- Crear la comisión de control y seguimiento legislativo con facultades suficientes para verificar la aplicación de las leyes; Inciso 18.- Disponer con los dos tercios de la totalidad de los miembros de la Cámara la intervención de los municipios con arreglo a lo previsto en esta Constitución; Inciso 19.- Dictar las leyes de organización y los códigos: rural, de Procedimientos judiciales, contencioso administrativo, electoral, bromatológico, de recursos renovables y no renovables y otros que sean necesarios y que correspondan a la competencia de la provincia; Inciso 20.- Proveer lo conducente a la prosperidad de la provincia, justicia, seguridad social, higiene, moralidad, cultura y todo lo que tienda a lograr la justicia social; Inciso 21.- Reglamentar el ejercicio de las profesiones liberales en cuanto no sea la competencia del gobierno de la Nación; Inciso 22.- Dictar las leyes conducentes a la organización y funcionamiento de la educación en la provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-106', lawId: 'const-la-rioja', number: '106', title: 'Origen de las leyes', text: `Las leyes pueden tener origen en proyectos presentados por uno o más diputados, por el Gobernador o por el Tribunal Superior de Justicia, en los casos autorizados en esta Constitución. Ningún proyecto de ley desechado totalmente por la Cámara podrá ser tratado nuevamente durante el año de su rechazo.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-107', lawId: 'const-la-rioja', number: '107', title: 'Promulgación y veto', text: `Cuando un proyecto de ley fuere sancionado por la Cámara, esta lo remitirá dentro de los cinco días al gobernador para su promulgación y publicación. El gobernador podrá vetar dicho proyecto en el término de diez días hábiles, en forma total o parcial. Si no lo hiciere se considerará promulgado. Vetada en todo o en parte una ley sancionada volverá con sus objeciones a la Cámara y si esta insistiere en su sanción con dos tercios de votos de los miembros presentes, será ley y pasará al gobernador para su promulgación. No concurriendo los dos tercios para la insistencia, ni mayoría para aceptar las modificaciones propuestas por el gobernador, no podrá repetirse en las sesiones del mismo año. Vetada en parte la ley por el gobernador, este podrá promulgar la parte no vetada. Juicio Político. Ambito de aplicación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-108', lawId: 'const-la-rioja', number: '108', title: '', text: `El Gobernador, Vicegobernador, Ministros, Miembros del Tribunal Superior de Justicia, el Fiscal General, el Defensor General, el Fiscal de Estado y los miembros del Tribunal de Cuentas podrán ser denunciados ante la Cámara de Diputados por inhabilidad sobreviniente física o mental, por mal desempeño de sus funciones, falta de cumplimiento de los deberes a su cargo o por delitos comunes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-109', lawId: 'const-la-rioja', number: '109', title: 'División de la Cámara', text: `Anualmente, la Cámara en su primera sesión se dividirá por sorteo en dos salas, compuestas cada una por la mitad de sus miembros a los fines de la tramitación del Juicio Político. En caso de que la composición de la Cámara fuese impar, la sala segunda se integrará con un miembro más. La sala primera tendrá a su cargo la acusación y la sala segunda será la encargada de juzgar. Cada sala será presidida por un diputado elegido de su seno.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-110', lawId: 'const-la-rioja', number: '110', title: 'Sala acusadora', text: `La sala acusadora nombrará anualmente, en su primera sesión, una comisión de investigación de cinco miembros, no pudiendo facultar al presidente para que la nombre. Dicha comisión tendrá por objeto investigar la verdad de los hechos en que se funda la acusación, teniendo para tal efecto las más amplias facultades.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-111', lawId: 'const-la-rioja', number: '111', title: 'Comisión Investigadora', text: `La comisión investigadora practicará las diligencias en el término perentorio de cuarenta días y presentará el dictamen a la sala acusadora que podrá aceptarlo o rechazarlo, necesitando dos tercios de los votos de sus miembros presentes cuando fuere favorable a la acusación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-112', lawId: 'const-la-rioja', number: '112', title: 'Suspensión de funciones', text: `Desde el momento que la sala acusadora haya aceptado la acusación, el acusado quedará suspendido en el ejercicio de sus funciones sin goce de sueldo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-113', lawId: 'const-la-rioja', number: '113', title: 'Comisión Acusadora', text: `Admitida la acusación por la sala acusadora, ésta nombrará una comisión de tres de sus miembros para que la sostenga ante la segunda sala constituida en tribunal de sentencia, previo juramento prestado ante su presidente.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-114', lawId: 'const-la-rioja', number: '114', title: 'Sala de Sentencia', text: `La sala de sentencia procederá de inmediato al estudio de la acusación, prueba y defensa, para pronunciarse en definitiva en el término de treinta días. Vencido este término sin dictar el fallo condenatorio, el acusado volverá al ejercicio de sus funciones con derecho a percibir los haberes no cobrados sin que el juicio pueda repetirse por los mismos hechos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-115', lawId: 'const-la-rioja', number: '115', title: 'Pronunciamiento', text: `Ningún acusado podrá ser declarado culpable sino por el voto de los dos tercios de la totalidad de los miembros de la sala de sentencia. La votación será nominal, debiendo registrarse en el acta el voto de los diputados sobre cada uno de los cargos que contenga la acusación.-`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-116', lawId: 'const-la-rioja', number: '116', title: 'Efectos', text: `El fallo no tendrá más efecto que el de destituir al acusado, pudiendo inhabilitarlo para ejercer cargos públicos por tiempo determinado, quedando siempre sujeto a acusación, juicio y condena conforme a las leyes comunes y ante los tribunales ordinarios.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-117', lawId: 'const-la-rioja', number: '117', title: 'Procedimiento', text: `La Cámara dictará una ley de procedimientos para esta clase de juicios, garantizando el ejercicio del derecho de defensa.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-118', lawId: 'const-la-rioja', number: '118', title: 'Gobernador', text: `La Función Ejecutiva Provincial será desempeñada por el Gobernador, quien es el jefe político de la administración de la provincia o en su defecto por el Vicegobernador, quien además de ser titular de la Cámara de Diputados, aún cuando no reemplace al Gobernador podrá participar en los acuerdos de ministros y reuniones de gabinete. Ambos se eligen al mismo tiempo y por idéntico período.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-119', lawId: 'const-la-rioja', number: '119', title: 'Requisitos', text: `Para ser elegido Gobernador o Vicegobernador se requiere: 1.- Ser argentino nativo o naturalizado, con diez años de ejercicio efectivo de la ciudadanía. 2.- Tener treinta años de edad. 3.- Ser elector en la provincia y tener cinco años de residencia inmediata en la misma, a no ser que la ausencia sea debida a servicios prestados a la Nación o a la provincia. 4.- No ser parientes entre sí dentro del cuarto grado de consanguinidad o afinidad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-120', lawId: 'const-la-rioja', number: '120', title: 'Duración del Mandato', text: `El Gobernador y Vicegobernador serán elegidos directamente por el pueblo de la provincia a simple pluralidad de sufragios. Durarán en sus funciones el término de cuatro años, sin que evento alguno que lo haya interrumpido pueda motivar su prórroga. Podrán ser reelegidos o sucederse recíprocamente por un solo periodo consecutivo. Si han sido reelectos o se han sucedido recíprocamente, no pueden ser elegidos para ninguno de ambos cargos, sino con el intervalo de un período.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-121', lawId: 'const-la-rioja', number: '121', title: 'Juramento', text: `Al tomar posesión de sus cargos, el Gobernador y Vicegobernador prestarán juramento ante la Cámara de Diputados o en su defecto ante el Tribunal Superior de Justicia, de cumplir y hacer cumplir fielmente esta Constitución, la Constitución Nacional, las leyes de la Nación y de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-122', lawId: 'const-la-rioja', number: '122', title: 'Inmunidades', text: `El Gobernador y Vicegobernador tendrán desde su elección las mismas inmunidades e incompatibilidades que los diputados. Percibirán el sueldo que la Ley fije, el cual no podrá ser alterado durante el término de su mandato, salvo cuando la modificación fuere dispuesta con carácter general.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-123', lawId: 'const-la-rioja', number: '123', title: 'Residencia', text: `El Gobernador y Vicegobernador residirán en la ciudad Capital y no podrán ausentarse de la provincia por más de treinta días sin autorización de la Cámara de Diputados. Durante el receso de ésta sólo podrán ausentarse de la Provincia por motivos urgentes y por el tiempo estrictamente indispensable, previa autorización de la comisión de receso.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-124', lawId: 'const-la-rioja', number: '124', title: 'Acefalía', text: `En caso de muerte, destitución, renuncia, licencia, suspensión, enfermedad o ausencia del Gobernador, será reemplazado en el ejercicio de sus funciones por el Vicegobernador por todo el resto del período legal en las tres primeras situaciones y hasta que hubiere cesado la inhabilidad temporaria en las restantes. Si la inhabilidad temporaria afectare simultáneamente al Gobernador y Vicegobernador, se hará cargo de la Función Ejecutiva, hasta que aquella cese para alguno de ellos, el Vicepresidente Primero o Vicepresidente Segundo de la Cámara de Diputados.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-125', lawId: 'const-la-rioja', number: '125', title: 'Nueva elección', text: `Si antes de asumir el ciudadano electo Gobernador muriese, renunciare o no pudiese ocupar el cargo, se procederá de inmediato a una nueva elección. En caso de acefalía simultánea y definitiva del Gobernador y Vicegobernador faltando más de dos años para la expiración del mandato, las funciones ejecutivas serán ejercidas por el Vicepresidente Primero de la Cámara de Diputados o en su defecto por el Vicepresidente Segundo de la misma o por el Presidente del Tribunal Superior, en este orden quienes deberán convocar al pueblo de la Provincia a elección de Gobernador y Vicegobernador en el término de treinta días. No podrá ser candidato el funcionario que desempeñe interinamente el cargo de Gobernador. Faltando menos de dos años para la finalización del período, el funcionario que desempeñe la Función Ejecutiva convocará a la Cámara de Diputados dentro de los cinco días si esta se hallare en receso, o le hará saber las vacantes dentro de las veinticuatro horas si estuviese en sesiones, para que dentro de los cinco días en el primer caso y de los tres en el segundo, se reúna con el quórum de dos tercios como mínimo a fin de designar de entre sus miembros y por mayoría de votos al reemplazante de cada uno de los cargos vacantes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-126', lawId: 'const-la-rioja', number: '126', title: 'Deberes y Atribuciones', text: `El Gobernador es el representante legal del Estado provincial y jefe de la administración con los siguientes deberes y atribuciones: Inciso 1.- Participa en la formación de las leyes con arreglo a esta Constitución, las promulga y las hace ejecutar, facilitando su cumplimiento por medio de reglamentos. Puede ejercer el derecho de veto. Inciso 2.- Informa a la Cámara de Diputados, al iniciarse cada período de sesiones ordinarias, el estado general de la administración, el movimiento de fondos que hubiese producido dentro y fuera del Presupuesto General durante el ejercicio económico anterior y las necesidades públicas y sus soluciones inmediatas. Inciso 3.- Convoca a elecciones en los casos y épocas determinadas en esta Constitución y leyes respectivas, sin que por ningún motivo puedan ser diferidas. Inciso 4.- Convoca a la Cámara de Diputados, a sesiones extraordinarias. Inciso 5.- Presenta el proyecto de Ley de Presupuesto y recursos, hace Recaudar las rentas de la provincia, decreta su inversión con arreglo a la ley y publica trimestralmente el estado de tesorería. Inciso 6.- Nombra y remueve a los ministros y a todos los funcionarios de la administración pública para los cuales no se haya previsto otra forma de nombramiento o remoción, conforme a la ley que reglamente los mismos. Inciso 7.- Otorga jubilaciones, pensiones, retiros y demás beneficios sociales conforme a la ley. Inciso 8.- Concede indultos y conmuta penas, previo informe del Tribunal Superior de Justicia, con`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-12º', lawId: 'const-la-rioja', number: '12º', title: '', text: `Artículo 12º de esta Constitución y de los cometidos por funcionarios sometidos al procedimiento del Juicio Político. Inciso 9.- Ejerce el poder de policía. Inciso 10.- Propone los miembros del Tribunal Superior de Justicia. Inciso 11.- Ejerce la fiscalización, control y tutela de los entes descentralizados, empresas del Estado o con participación estatal y sociedades o asociaciones con personaría jurídica para asegurar el cumplimiento de los fines respectivos. Inciso 12.- No podrá en ningún caso, bajo de pena de nulidad absoluta e insanable emitir disposiciones de carácter legislativo. Solamente cuando circunstancias excepcionales hicieran imposible seguir los trámites ordinarios previstos para la sanción de las leyes, y no se trate de normas que regulen materia tributaria, electoral, ni la intervención a los municipios, podrá dictar decretos por razones de necesidad y urgencia, los que deberán ser refrendados por todos los ministros. En un plazo no mayor a diez días en el período ordinario de sesiones, el Ejecutivo deberá enviar el decreto para la ratificación de la Legislatura Provincial, la que en un máximo de treinta días deberá expedirse al respecto. Transcurrido dicho término sin que la Cámara se expida el decreto se considerará aprobado. Ministros`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-127', lawId: 'const-la-rioja', number: '127', title: 'excepción de las que recaigan con motivo de los delitos referidos en el', text: `El despacho de los asuntos de la Función Ejecutiva estará a cargo de ministros, cuyo número, funciones y departamentos determinará la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-128', lawId: 'const-la-rioja', number: '128', title: 'Condiciones', text: `Para ser ministro se requieren las mismas condiciones que para ser diputado y no ser cónyuge del Gobernador ni pariente dentro del cuarto grado de consanguinidad o afinidad. Rigen además iguales incompatibilidades.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-129', lawId: 'const-la-rioja', number: '129', title: 'Competencia y Responsabilidades', text: `Los ministros refrendan y legalizan con su firma las resoluciones del Gobernador, sin la cual no tendrán efecto. Son solidariamente responsables. Sólo podrán resolver por si mismos en lo referente al régimen económico y administrativo de sus respectivas áreas y dictar providencias de trámite. Los ministros de la Función Ejecutiva provincial presentarán semestralmente una memoria detallada del estado de la provincia en lo relativo a los asuntos de sus áreas. Asimismo, podrán concurrir a las sesiones de la Cámara y tomar parte en sus debates, pero no votar.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-130', lawId: 'const-la-rioja', number: '130', title: 'Organismos descentralizados', text: `El Gobernador podrá delegar en entidades descentralizadas con personalidad jurídica parte de sus funciones administrativas a los fines de la prestación de un servicio público determinado. Las entidades descentralizadas estarán siempre bajo el control directo del Gobernador por intermedio del ministerio del área de su competencia. Deberán ser creadas por ley, la que establecerá las normas generales de su organización y funcionamiento. A los fines de este artículo, la Función Ejecutiva deberá coordinar con los Respectivos gobiernos municipales el accionar de estas entidades, otorgándoles la necesaria participación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-131', lawId: 'const-la-rioja', number: '131', title: 'PRINCIPIOS GENERALES Funciones e independencia', text: `Sólo el Tribunal Superior y demás jueces ejercen la función jurisdiccional; tienen a su cargo la guarda de la soberanía del pueblo, la custodia de la supremacía constitucional y la protección de los derechos y garantías. El Tribunal Superior y demás jueces tendrán el imperio necesario para mantener su inviolabilidad e independencia ante los órganos que ejercen las otras funciones del Estado. En el ámbito de sus atribuciones, su potestad es exclusiva, no pudiendo el Gobernador ni la Cámara de Diputados en ningún caso ejercer funciones judiciales, arrogarse el conocimiento de juicios pendientes, ni restablecer los que hubieren concluido.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-132', lawId: 'const-la-rioja', number: '132', title: 'Composición', text: `La Función Judicial será desempeñada por un Tribunal Superior de Justicia, cámaras, jueces, jueces de paz letrados o legos, miembros de los Ministerios Públicos y demás tribunales, juzgados y funcionarios que establezca la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-133', lawId: 'const-la-rioja', number: '133', title: 'Inmunidades', text: `Los jueces y miembros de los Ministerios Públicos, gozarán de las mismas inmunidades que los diputados. Reciben por sus servicios una compensación mensual que determina la ley y no podrán ser disminuidas con descuentos que no sean los que se dispusieren con fines de previsión o con carácter general. La inamovilidad comprende el grado y la sede, no pudiendo ser trasladados sin su consentimiento. Conservarán sus cargos mientras dure su idoneidad. Sólo podrán ser removidos en la forma y por las causas previstas en esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-134', lawId: 'const-la-rioja', number: '134', title: 'Incompatibilidades', text: `Sin perjuicio de las demás incompatibilidades que surjan de esta Constitución y de la naturaleza de la Función Judicial, a los jueces y miembros de los Ministerios Públicos les está prohibido participar en organizaciones o actividades políticas, ejercer su profesión, exceptuándose los casos en que actúen por derecho propio, desempeñar empleos, funciones u otras actividades dentro y fuera de la Provincia con excepción de la docencia o ejecutar actos que comprometan su imparcialidad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-135', lawId: 'const-la-rioja', number: '135', title: 'Etica', text: `Los jueces y miembros de los Ministerios Públicos deberán desempeñarse observando una conducta ejemplar en todas sus actividades, tanto oficiales como privadas de tal forma que ese comportamiento mantenga y promueva la confianza pública. Esta norma comprende la obligación de actuar respetando los principios y pautas éticas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-136', lawId: 'const-la-rioja', number: '136', title: 'Competencia', text: `Son de competencia del Tribunal Superior de Justicia y de los tribunales inferiores todas las causas que versen sobre puntos regidos por la Constitución Nacional, esta Constitución, las leyes nacionales y provinciales, cartas orgánicas y ordenanzas municipales según que las personas o las cosas caigan bajo la jurisdicción de la provincia. Quedan excluidas de su conocimiento las causas atribuidas por esta Constitución al tribunal de juicio político o jurado de enjuiciamiento.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-137', lawId: 'const-la-rioja', number: '137', title: '', text: `El Tribunal Superior estará integrado por cinco miembros y podrán dividirse en salas. La presidencia del Cuerpo será desempeñada anualmente por turno por cada uno de sus miembros, elegido por simple mayoría, pudiendo ser reelegido. Los miembros del Tribunal Superior, serán designados por la Cámara de Diputados a propuesta del Gobernador en sesión pública, y juran ante el propio Cuerpo. Se remueven por las causales establecidas en esta constitución y procedimiento del juicio político.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-138', lawId: 'const-la-rioja', number: '138', title: 'Atribuciones y Deberes', text: `El Tribunal Superior tiene las siguientes atribuciones y deberes: 1. Representa los órganos que desempeñan la Función Judicial y ejerce la superintendencia sobre sus órganos jurisdiccionales y administrativos que conforman la administración de justicia. 2. Nombra a los empleados y funcionarios de la Función Judicial, no pudiendo removerlos sin sumario previo. 3. Ejerce jurisdicción en el régimen interno de las cárceles. 4. Dicta el reglamento interno, atendiendo a los principios de celeridad, eficiencia y descentralización. 5. Interviene especialmente con facultades de superintendencia en las Denuncias que las partes efectúen sobre "pérdida de la competencia de los jueces" y acreditado que fuera la misma, comunica inmediatamente al Consejo de la Magistratura para su intervención. Su omisión será motivo de juicio político. 6. Remite cada tres meses a la Cámara de Diputados, y al Gobernador, una Memoria del estado y necesidades de la administración de justicia. 7. Propondrá, anualmente, al Gobernador el presupuesto de gastos de la Administración de justicia para su consideración por la legislatura, dentro del presupuesto general de la provincia. 8. Semestralmente hace conocer a la Cámara de Diputados, a los fines de los controles intrapoderes, la cantidad de resoluciones y sentencias dictadas por cada tribunal, y las recusaciones e inhibiciones de cada juez, los que deberán estar de acuerdo a los parámetros de gestión establecidos por el Tribunal Superior. A tales efectos auditará periódicamente en el ejercicio de la superintendencia los distintos juzgados y tribunales, y podrá requerir los mismos informes al Ministerio Público. 9. Puede enviar a la Cámara de Diputado, con carácter de iniciativa, proyectos de leyes sobre organización y funcionamiento de la administración de justicia, de la policía judicial, y creación de servicios conexos, como asimismo los códigos, leyes de procedimientos judiciales y sus modificaciones. En estos casos el presidente del Tribunal Superior de Justicia o miembro que el Tribunal designe, podrá concurrir a las comisiones legislativas o a la sesión de Cámara para fundar el proyecto o aportar datos e informes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-139', lawId: 'const-la-rioja', number: '139', title: 'Competencia', text: `El Tribunal Superior ejerce competencia originaria y exclusiva: 1. En las demandas que se promuevan directamente por vía de acción por inconstitucionalidad de leyes, decretos, ordenanzas y reglamentos. 2. En los conflictos de competencia entre las funciones del Estado Provincial, entre estas y las municipalidades o de las municipalidades entre sí y los que se susciten entre las Cámaras o jueces o entre uno de estos o cualquier autoridad ejecutiva, con motivo de sus respectivas jurisdicciones. 3. En las causas contencioso-administrativas, previa denegación de autoridad competente al reconocimiento de los derechos que se gestionen por parte interesada. La ley establecerá término y procedimiento para este recurso, y también podrá según la oportunidad y conveniencia futuras, crear un fuero contencioso-administrativo al cual le trasladará esta competencia. Ejerce jurisdicción recurrida como tribunal de casación, inconstitucionalidad, revisión y demás casos que establezca la ley. Conoce de las resoluciones que produzca el Tribunal de Cuentas según la forma y procedimiento que determine la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-140', lawId: 'const-la-rioja', number: '140', title: 'DE LA ADMINISTRACIÓN DE JUSTICIA Aplicación del derecho', text: `El juez tiene el deber de mantener la supremacía constitucional, siendo el control de constitucionalidad cuestiones de derecho. El juez a pedido de parte o de oficio debe siempre verificar la constitucionalidad de las normas que aplica. El juez aplicará el derecho con prescindencia o en contra de la opinión jurídica de las partes, interpretando siempre la ley o doctrina legal con un criterio jurídico de actualidad, de modo que su aplicación importe la realización de la justicia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-141', lawId: 'const-la-rioja', number: '141', title: 'Requisitos', text: `Para ser juez se requiere título de abogado, ocho años de ejercicio profesional o de desempeño en la magistratura y treinta años de edad. En todos los casos se requiere ser argentino con dos años de residencia y matrícula de abogado efectivas e inmediatas, y previos a su designación en la provincia. Para ser juez de paz lego se requiere veinticinco años de edad, título secundario y ser argentino con dos años de residencia efectiva, inmediatos y previos a su designación en el departamento del juzgado. COMPETENCIA, JURISDICCIÓN`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-142', lawId: 'const-la-rioja', number: '142', title: 'Y FUNCIONAMIENTO DE LOS TRIBUNALES', text: `Una ley orgánica determinará la organización y atribuciones de los tribunales y juzgados que fueren necesarios para una eficaz administración de justicia en todo el territorio de la provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-143', lawId: 'const-la-rioja', number: '143', title: 'Pérdida de la competencia', text: `Vencidos los plazos estableci dos por ley para que los jueces dicten sus resoluciones, y previo pedido de pronto despacho, perderán la competencia de pleno derecho, sin necesidad de declaración alguna, si no la dictaran en el término legal establecido para las mismas. La competencia en estos casos deberá ser ejercida por el subrogante legal que corresponda. Los jueces que por tercera vez en el año pierdan el ejercicio de la competencia quedan sometidos a juicio político o jurado de enjuiciamiento según sea el caso, lo que de por sí no constituye una sanción, sino sólo un instrumento para determinar si hubo descuido del deber o inconducta en el desempeño del cargo y se lo establece como medio para proteger los derechos del pueblo. El juez que, perdida la competencia de pleno derecho, no pasara las actuaciones al subrogante legal será pasible de las sanciones civiles, penales y políticas que determinen las leyes y esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-144', lawId: 'const-la-rioja', number: '144', title: 'Sistema judicial', text: `En la Provincia se aplicará el sistema oral en toda clase de procesos judiciales, y las cuestiones que se planteen en todas sus instancias se resolverán en audiencias públicas y contradictorias, cumpliendo con el principio de una justicia efectivamente rápida y eficiente. La ley determinará la utilización de mecanismos alternativos de resolución de conflictos que disminuyan y pongan fin a la judicialización de los litigios. Se promoverá la instalación del juicio por jurado en la medida y oportunidad que la ley lo establezca.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-145', lawId: 'const-la-rioja', number: '145', title: 'Policía Técnica Judicial', text: `La Policía Técnica Judicial es un Servicio de la justicia. Depende del Tribunal Superior de Justicia y tiene por objetivo, entre otros, para la averiguación del delito: el descubrimiento, consolidación, fortalecimiento y confirmación de las pruebas. Actúa a disposición de los jueces y del Ministerio Público, según lo requieran y en los términos que la ley establezca. Se organiza de acuerdo a esta Constitución y a la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-146', lawId: 'const-la-rioja', number: '146', title: 'DE LOS MINISTERIOS PÚBLICOS Principios Generales', text: `El Ministerio Público Fiscal y el Ministerio Público de la Defensa son órganos que integran la Función Judicial; tienen autonomía funcional y autarquía financiera, y ejercen sus funciones por medio de órganos propios conforme a los principios de unidad de actuación, de legalidad y objetividad. El Ministerio Público Fiscal y el Ministerio Público de la Defensa están integrados y dirigidos por el Fiscal General, y el Defensor General respectivamente, y compuestos por los demás integrantes que establezca la ley; ejercen la representación de sus ministerios y tienen la superintendencia administrativa de los miembros, funcionarios y empleados que están a su cargo. El Fiscal General, y el Defensor General son designados por la Cámara de Diputados a propuesta del Gobernador y juran el cargo ante el Tribunal Superior de Justicia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-141°', lawId: 'const-la-rioja', number: '141°', title: '', text: `El Fiscal General y el Defensor General se remueven por las causales y el procedimiento del juicio político. Los miembros del Ministerio Público Fiscal y el Ministerio Público de la Defensa no pueden subrogarse recíprocamente. Lo dispuesto en el`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-143°', lawId: 'const-la-rioja', number: '143°', title: '', text: `Artículo 143°, de esta constitución, también es aplicable a los miembros del Ministerio Público.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-147', lawId: 'const-la-rioja', number: '147', title: 'Los requisitos para acceder a ambos cargos son los establecidos en el', text: `El Tribunal de Cuentas con jurisdicción en toda la Provicia estará integrado por un presidente, un vicepresidente y tres vocales, los que durarán en sus funciones seis años, pudiendo ser reelegidos. Durante ese término sólo podrán ser removidos por las causas y el procedimiento establecido para el tribunal de juicio político. Para ser designado miembro del Tribunal de Cuentas se requiere ser abogado o contador público y reunir las condiciones para ser diputado. Tres serán abogados y dos contadores.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-148', lawId: 'const-la-rioja', number: '148', title: 'Requisitos', text: `Para ser Fiscal de Cámara, o Agente Fiscal, se`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-141°-2', lawId: 'const-la-rioja', number: '141°', title: '', text: `Asistencia y Derechos de la víctima`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-149', lawId: 'const-la-rioja', number: '149', title: 'Requiere los mismos requisitos establecidos en el', text: `Se considera víctima a la persona directamente ofendida por el delito, a sus derechohabientes, su cónyuge o la persona que convivía con ella en el momento de la comisión del delito ligada por vínculos especiales de afecto. En todo proceso penal deberá actuarse de manera tal que la víctima no sea revictimisada, se la ignore o menosprecie. La víctima tendrá derecho a recibir un trato digno y respetuoso; a que se hagan mínimas sus molestias derivadas del procedimiento; a la salvaguarda de su intimidad en la medida en que no obstruya la investigación y a la exclusión de la publicidad en los actos en los que intervenga; a ser informada acerca del estado y trámite de la causa, el resultado del acto procesal en el que ha participado y sobre la situación del imputado; podrá proponer diligencias para una mejor averiguación de la verdad. Para el ejercicio de los derechos que se le acuerdan a quien alega su condición de víctima, no será obligatorio el patrocinio letrado. Sin perjuicio de la posibilidad de constituirse como querellante particular o actor civil, la víctima podrá intervenir en el proceso penal.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-150', lawId: 'const-la-rioja', number: '150', title: 'Funciones', text: `El Ministerio Público de la Defensa, compuesto por el Defensor General, los Defensores, Asesores de Menores e Incapaces, funcionarios y aquellos que la ley determine, tienen por funciones, además de las otras que por ley se le establezcan: disponer la adopción de todas las medidas que sean necesarias y conducentes para el ejercicio de las funciones y atribuciones que la Constitución provincial, las leyes y los reglamentos le confieran; realizar todas las acciones conducentes para la defensa y protección de los derechos humanos; promover y ejecutar políticas para facilitar el acceso a la justicia de los sectores discriminados, de los niños y de los incapaces; asegurar en todas las instancias y en todos los procesos en que se ejerza la representación y defensa oficial, la debida asistencia de cada una de las partes con intereses contrapuestos, de los niños, o de los discapacitados; coordinar las actividades con las diversas autoridades provinciales y municipales, especialmente con las que cumplan funciones de instrucción criminal y policía judicial. Una ley determinará la organización y atribuciones del Ministerio Público de la Defensa.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-151', lawId: 'const-la-rioja', number: '151', title: 'Requisitos', text: `Para ser Defensor Oficial o Asesor de Menores e Incapaces, se`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-141°-3', lawId: 'const-la-rioja', number: '141°', title: '', text: `SECCIÓN 5 ÓRGANOS DE SELECCIÓN Y REMOCIÓN Selección y Remoción`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-152', lawId: 'const-la-rioja', number: '152', title: 'requiere los mismos requisitos establecidos en el', text: `Previo a su designación como integrante de la Función Judicial, para acceder a los cargos de jueces, o miembros de los Ministerios Públicos, los interesados serán seleccionados mediante un examen de idoneidad en concurso público por ante el Consejo de la Magistratura. Los jueces y miembros de los Ministerios Públicos que prevé esta Constitución, se remueven por las causales del juicio político, por las demás que establece esta Constitución, y procedimiento ante el Jurado de Enjuiciamiento. Es incompatible el ejercicio del cargo de miembro del Consejo de la Magistratura con el de miembro del Jurado de Enjuiciamiento.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-153', lawId: 'const-la-rioja', number: '153', title: 'DEL CONSEJO DE LA MAGISTRATURA Integración', text: `El Consejo de la Magistratura, regulado por una ley especial sancionada por las dos terceras partes de la totalidad de los miembros de la Cámara de Diputados, funcionará en el ámbito del Tribunal Superior de Justicia, que ejercerá su presidencia, y se integrará cada dos años, sin reelección inmediata, con: tres diputados, uno por la minoría, y dos representantes de la Función Ejecutiva; un representante de los jueces inferiores elegido al efecto por sus pares, y uno de los abogados de la matrícula elegido por el voto directo de todos los letrados matriculados de la provincia; asimismo, podrá ser integrado por personas del ámbito académico en la forma y número que indique la ley, debiendo considerarse preferentemente a tal efecto a docentes de las carreras de derecho. Cuando el concurso sea para cubrir cargos del Ministerio Público Fiscal o del Ministerio Público de la Defensa, la presidencia del Cuerpo la ejercerá el Fiscal General o el Defensor General según correspondiere, y el representante de los jueces inferiores será reemplazado por el representante del Ministerio Público que concerniere al cargo que se concurse. La ley completará la modalidad de su funcionamiento.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-154', lawId: 'const-la-rioja', number: '154', title: 'Atribuciones y Deberes', text: `El Consejo de la Magistratura tiene las siguientes atribuciones y deberes: 1. Efectúa la selección de todos los jueces y miembros del Ministerio Público para cubrir los cargos vacantes de la Función Judicial. 2. Cubre las vacantes que se produzcan de manera transitoria, no pudiendo Exceder esas designaciones el plazo de seis meses. 3. Puede cubrir los cargos que requieran suplencias temporales, no pudiendo exceder en este caso el plazo de la ausencia. 4. Recibe las denuncias en contra de jueces o miembros del Ministerio Público Y decide la apertura del jurado de enjuiciamiento, o la remisión de las Actuaciones al Tribunal Superior de Justicia para que ejerza la superintendencia e imponga, en el caso de ser pasible, las sanciones administrativas que la ley prevea. 5. Somete a jurado de enjuiciamiento al juez que pierda la competencia por más de tres veces al año. El Consejo de la Magistratura examinará las idoneidades psicofísicas, científico - técnica, gerencial y ética de los aspirantes en concurso público y abierto, y sus resoluciones serán fundadas. No puede presentarse al concurso del cargo vacante, el juez designado transitoriamente para cubrir ese cargo. Ningún concurso desde su convocatoria hasta la designación podrá demorar más de ciento veinte días corridos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-155', lawId: 'const-la-rioja', number: '155', title: 'Designaciones', text: `El Consejo de la Magistratura elevará una nómina de tres postulantes en condiciones de cubrir el cargo a la Cámara de Diputados quien elegirá a uno respetando el orden de mérito, pudiendo alterarlo fundadamente, y le otorgará acuerdo en sesión pública. Agotada la lista, sin que la Cámara haya designado a ninguno de sus integrantes, el Consejo deberá convocar a nuevo concurso.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-156', lawId: 'const-la-rioja', number: '156', title: '', text: `El Jurado de Enjuiciamiento, regulado por una ley especial sancionada por las dos terceras partes de la totalidad de los miembros de la Cámara de Diputados, tendrá a su cargo la remoción de los jueces y miembros del Ministerio Público de la Función Judicial. Es integrado por un presidente que será miembro del Tribunal Superior de Justicia, tres diputados, uno por la minoría, un representante del Poder Ejecutivo; y un abogado de la matrícula elegido por el voto directo de todos los letrados matriculados de la provincia, y se integrará cada dos años, sin reelección inmediata; funcionará en el ámbito del Tribunal Superior de Justicia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-157', lawId: 'const-la-rioja', number: '157', title: 'Trámite y Procedimiento', text: `Decidida la apertura del juicio en contra del juez o miembro del Ministerio Público por parte del Consejo de la Magistratura, se integrará, por sorteo del que estará exento el presidente del Consejo, una comisión investigadora y de acusación de tres miembros que llevará adelante la acusación ante el Jurado de Enjuiciamiento. Desde el momento de la apertura, el acusado quedará suspendido en el ejercicio de sus funciones. Todo este trámite deberá efectivizarse en un plazo de treinta días hábiles, prorrogables por quince días hábiles más. En el juicio se actuará con las garantías del debido proceso, la acusación, defensa, prueba, contradicción y sentencia con voto fundado de cada uno de los miembros del jurado, y dictará sentencia por una mayoría de dos tercios de los votos de todos los miembros de acuerdo a las reglas de la sana crítica, para destituir al acusado. Su fallo, que será irrecurrible, no tendrá más efecto que la destitución del acusado. Pero la parte condenada quedará no obstante sujeta a acusación, juicio y castigo conforme a las leyes ante los tribunales ordinarios. Corresponderá archivar las actuaciones y, en su caso, reponer al juez o miembro del Ministerio Público suspendido, si transcurrieren sesenta días hábiles, contados desde la decisión de abrir el procedimiento de remoción, sin que haya sido dictado el fallo. El Jurado podrá determinar otro tipo de sanciones, que la ley deberá prever, para el caso de entender que no corresponde la remoción del juez o miembro del Ministerio Público enjuiciado, pudiendo llegar hasta la declaración de inocencia de los cargos imputados, con los que corresponderá la reposición en el cargo. El denunciado podrá designar para su defensa un Defensor Oficial. Una ley especial podrá completar la modalidad del funcionamiento y procedimiento ante el Jurado de Enjuiciamiento.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-158', lawId: 'const-la-rioja', number: '158', title: 'CAPÍTULO IX ÓRGANOS DE FISCALIZACIÓN Y ASESORAMIENTO DEFENSOR DEL PUEBLO', text: `El Defensor del Pueblo es un órgano independiente instituido en el ámbito de la Legislatura Provincial, que actuará con plena autonomía funcional, sin recibir instrucciones de ninguna autoridad. Su misión fundamental será la defensa de los derechos, garantías e intereses tutelados en esta Constitución y las leyes ante hechos, actos u omisiones de la administración pública provincial y municipal, de empresas públicas o privadas prestatarias de servicios públicos, o cuando por cualquier motivo se vean afectados los recursos naturales o se altere el normal desarrollo del medio ambiente humano. Es designado por la Legislatura Provincial con el voto de las dos terceras partes de los miembros presentes. Durará en su cargo cinco años pudiendo ser reelegido. La organización y funcionamiento de esta institución serán regulados por una ley especial, preservando la gratuidad de las actuaciones para el administrado. El Defensor del Pueblo tendrá legitimación procesal únicamente en los casos en que la ley especial determine.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-159', lawId: 'const-la-rioja', number: '159', title: 'FISCAL DE ESTADO Funciones', text: `El Fiscal de Estado es el encargado de la defensa judicial de los intereses públicos y privados de la provincia y del patrimonio fiscal. Tendrá personería para demandar la nulidad e inconstitucionalidad de leyes, decretos, reglamentos, contratos o resoluciones en el solo interés de la ley o en defensa de los intereses fiscales de la provincia. Será también parte en los procesos que se formen ante el Tribunal de Cuentas. La ley reglamentará sus funciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-160', lawId: 'const-la-rioja', number: '160', title: 'Nombramiento', text: `Para ser Fiscal de Estado se requieren las mismas condiciones que para ser miembro del Tribunal Superior de Justicia, teniendo iguales derechos, incompatibilidades e inmunidades. Será designado por el Gobernador con acuerdo de la Cámara de Diputados por un término de cuatro años y podrá ser reelegido. En ese período será inamovible y sólo podrá ser removido por las causas y el procedimiento establecido para el juicio político. TRIBUNAL DE CUENTAS Integración.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-161', lawId: 'const-la-rioja', number: '161', title: '', text: `El Tribunal de Cuentas con jurisdicción en toda la Provincia estará integrado por un Presidente, un Vicepresidente y tres Vocales, los que durarán en sus funciones seis años, pudiendo ser reelegidos. Durante ese término sólo podrán ser removidos por las causas y el procedimiento establecido para el tribunal de juicio político. Para ser designado miembro del Tribunal de Cuentas se requiere ser abogado o contador público y reunir las condiciones para ser diputado. Tres serán abogados y dos contadores.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-162', lawId: 'const-la-rioja', number: '162', title: 'Designación', text: `El Presidente, el Vicepresidente y uno de los Vocales serán designados por la Cámara de Diputados a propuesta del bloque mayoritario. Los dos vocales restantes a propuesta de cada bloque de los partidos que Hubieren obtenido representación en ese cuerpo, en orden sucesivo al bloque mayoritario. En caso de existir una sola minoría, esta propondrá a ambos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-163', lawId: 'const-la-rioja', number: '163', title: 'Atribuciones', text: `El Tribunal de Cuentas tendrá las siguientes atribuciones: controlar la legitimidad en la percepción e inversión de caudales efectuadas por los funcionarios y empleados públicos, entes de la administración centralizada, descentralizada y municipales, empresas públicas o con participación estatal e instituciones privadas que administren fondos del Estado, los que estarán obligados a remitir las cuentas documentadas de los dineros que hubieren invertido o percibido para su aprobación o desaprobación; inspeccionar las oficinas provinciales y municipales que administren fondos públicos e instituciones en que el Estado tenga intereses y tomar las medidas necesarias para prevenir cualquier irregularidad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-164°', lawId: 'const-la-rioja', number: '164°', title: '', text: `Los fallos que emita el Tribunal harán cosa juzgada en cuanto a si la percepción e inversión de fondos ha sido hecha o no de acuerdo a esta constitución y las normas jurídicas respectivas, siendo susceptibles de los recursos que la ley establezca por ante el Tribunal Superior de Justicia. Si en el curso del trámite administrativo surgiere la posible comisión de un hecho delictivo, se remitirán las actuaciones respectivas al juez competente. Ley Orgánica`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-165°', lawId: 'const-la-rioja', number: '165°', title: '', text: `-. La Cámara de Diputados dictará la ley orgánica que reglamentará las funciones del Tribunal de Cuentas. Cuando en las cartas orgánicas municipales se creare el Tribunal de Cuentas, no se aplicarán las disposiciones de este título.- ASESOR GENERAL DE GOBIERNO Funciones y`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-166', lawId: 'const-la-rioja', number: '166', title: '', text: `El Asesor General de Gobierno tendrá las funciones de asesorar al Gobernador y reparticiones de la administración pública, con excepción de las entidades descentralizadas y presidirá el cuerpo de abogados del Estado. Para ser Asesor General de Gobierno se requieren las mismas condiciones que para Fiscal de Estado. La Ley reglamentará su organización y funcionamiento.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-167', lawId: 'const-la-rioja', number: '167', title: 'CONSEJO ECONÓMICO Y SOCIAL Funciones', text: `En el ámbito de la Función Ejecutiva funcionará el Consejo Económico Social, con la finalidad de asegurar la participación a través de la opinión no vinculante de los sectores representativos de la producción y de las áreas económicas y sociales de la comunidad en el orden provincial y regional Tendrá como función actuar como órgano consultivo en la elaboración del Presupuesto provincial y/o regional, procurando la participación sectorial para conocer el orden de prioridades en la distribución del gasto público y fortalecimiento de la conciencia tributaria en la provincia y en cada uno de los departamentos. Propenderá a la orientación del presupuesto hacia la producción, incentivando el desarrollo de las fuentes de trabajo y participando en la ejecución de las políticas sociales. La ley determinará las formas de constitución, funcionamiento y competencia territorial por regiones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-168°', lawId: 'const-la-rioja', number: '168°', title: '', text: `Los Municipios tienen autonomía institucional, política, administrativa, económica y financiera. La Legislatura Provincial sancionará un régimen de coparticipación municipal en el que la distribución entre la provincia y los municipios se efectúe en relación directa a las competencias, servicios y funciones de cada uno de ellos, contemplando criterios objetivos de reparto y sea equitativa, proporcional y solidaria, dando prioridad al logro de un grado equivalente de desarrollo, calidad de vida e igualdad de oportunidades. La autonomía que esta Constitución reconoce no podrá ser limitada por ley ni autoridad alguna. Deberán dictar su propia Carta Orgánica, con arreglo a lo que disponen los Artículos 169º y 172º, a cuyos fines convocarán a una Convención Municipal, la que estará integrada por un número igual al de los miembros del Concejo Deliberante y serán elegidos directamente por el pueblo del departamento ORGANIZACIÓN.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-169', lawId: 'const-la-rioja', number: '169', title: '', text: `El Gobierno Municipal se compone de un Departamento Ejecutivo y otro Deliberativo. El Departamento Ejecutivo será ejercido por una persona con el título de Intendente, elegido`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-171°', lawId: 'const-la-rioja', number: '171°', title: '', text: `El Departamento Deliberativo será presidido por un Viceintendente, elegido de igual forma que el Intendente a quien reemplazará en caso de ausencia, renuncia, fallecimiento, o inhabilidad. El Departamento Deliberativo será desempeñado por un cuerpo que se Denominará Concejo Deliberante y estará compuesto por concejales. Los concejales percibirán por su actividad una dieta establecida por ordenanza, acorde a los gastos que demande la actividad y que no excederá de la remuneración que por todo concepto perciba el Intendente. Se integrará sobre la siguiente base poblacional: Hasta 10.000 habitantes 7 concejales De 10.001 a 15.000 habitantes 9 concejales De 15.001 a 45.000 habitantes 11 concejales De 45.001 a 100.000 habitantes 13 concejales De 100.001 habitantes en adelante 15 concejales.- EJIDO MUNICIPAL.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-170', lawId: 'const-la-rioja', number: '170', title: 'de conformidad al', text: `El ejido municipal coincidirá con los límites del Departamento de conformidad a lo previsto en el`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-168°-2', lawId: 'const-la-rioja', number: '168°', title: '', text: `CONDICIONES Y MANDATO.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-171', lawId: 'const-la-rioja', number: '171', title: '', text: `Los Intendentes y Viceintendentes serán elegidos directamente y a simple pluralidad de sufragios por el pueblo del municipio y durarán cuatro años en sus funciones, pudiendo ser reelectos en las mismas condiciones que para Gobernador y Vicegobernador. Los concejales serán elegidos directamente por el pueblo del municipio, aplicándose el sistema D' Hont`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-81°-2', lawId: 'const-la-rioja', number: '81°', title: '', text: `Artículo 81°, segundo párrafo, pudiendo ser reelectos. Para ser Intendente, Viceintendente, o Concejal se requieren las mismas condiciones que para ser diputado provincial. CARTAS ORGÁNICAS. ATRIBUCIONES.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-172', lawId: 'const-la-rioja', number: '172', title: 'para la distribución de los cargos y respetando lo establecido en el', text: `Las Cartas Orgánicas Municipales establecerán las estructuras funcionales del municipio, conforme a los requerimientos del Departamento, incorporando los aspectos de educación, salud pública, gobierno y cultura, hacienda, obras y servicios públicos, y el desarrollo social y económico. Las Cartas Orgánicas deberán asegurar: 1. Órganos de fiscalización y contralor, tales como la Fiscalía Municipal y Tribunal de Cuentas, como así también deberán asegurar la Justicia Municipal de Faltas. 2. Los derechos de iniciativa, consulta, revocatoria y audiencias públicas. 3. El reconocimiento de centros vecinales. 4. El sistema de juicio político, estableciendo como condición para la suspensión o destitución la misma proporcionalidad establecida para el juicio político en la Cámara de Diputados. 5. El proceso de regionalización para el desarrollo económico y social, que permita la integración y coordinación de esfuerzos en pos de los intereses Comunes mediante acuerdos interdepartamentales, que podrán crear órganos con facultades para el cumplimiento de sus fines. Esta Constitución reconoce las siguientes regiones: Región 1: VALLE DEL BERMEJO: Vinchina, General Lamadrid, Coronel Felipe Varela. Región 2: VALLE DEL FAMATINA: Famatina, Chilecito. Región 3: NORTE: Arauco, Castro Barros, San Blas de Los Sauces. Constitución de La Provincia de La Rioja - 42 - Región 4: CENTRO: Capital, Sanagasta. Región 5: LLANOS NORTE: Independencia, Ángel Vicente Peñaloza, Chamical, General Belgrano. Región 6: LLANOS SUR: General Juan Facundo Quiroga, Rosario Vera Peñaloza, General Ortíz de Ocampo, General San Martín. 6. La descentralización de la gestión de gobierno. 7. La defensa del medio ambiente, teniendo en cuenta lo que dispone esta Constitución. 8. La composición del patrimonio municipal y los recursos municipales. 9. Derechos del consumidor. Protección y defensa de los consumidores y usuarios. 10. Organización administrativa, debiéndose prever la descentralización de la misma. 11. Todos los demás requisitos que establece esta Constitución.- RECURSOS.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-173', lawId: 'const-la-rioja', number: '173', title: '', text: `Cada Municipio provee a los gastos de su administración con los fondos del tesoro municipal formado por el producido de la actividad económica que realice y los servicios que preste; con la participación, y en la forma que los municipios convengan con la provincia, del producido de los impuestos que el gobierno provincial o federal recaude en su jurisdicción; por la venta o locación de bienes del dominio municipal; por los recursos provenientes de empréstitos y otras operaciones de crédito que realice; por los subsidios que le acuerda el gobierno provincial o federal y por los demás ingresos provenientes de otras fuentes de recursos. INTERVENCIÓN.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-174', lawId: 'const-la-rioja', number: '174', title: '', text: `Los Municipios podrán ser intervenidos por ley aprobada con dos tercios de votos de los miembros de la Cámara de Diputados, en los siguientes casos: 1.- Cuando existiere acefalía, para asegurar la constitución de sus autoridades. 2.- Cuando no cumplieren con los servicios de empréstitos o si de dos ejercicios sucesivos resultare déficit susceptible de comprometer su estabilidad financiera. 3.- Para normalizar la situación institucional. Constitución de La Provincia de La Rioja 4.- Cuando expresamente lo prevea la Carta Orgánica Municipal. La Intervención se dispondrá por el término que fije la ley, debiendo el Interventor atender exclusivamente los servicios ordinarios.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-175', lawId: 'const-la-rioja', number: '175', title: '', text: `El Poder Constituyente será ejercido por una Convención integrada por igual número de miembros que la Cámara de Diputados y será el órgano competente para reformar esta Constitución en forma parcial o total. Los Convencionales Constituyentes deberán reunir las condiciones requeridas para ser diputado provincial y tendrán las mismas inmunidades y privilegios que estos, desde su elección hasta que concluyan sus funciones, teniendo las mismas incompatibilidades. DECLARACIÓN DE LA REFORMA.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-176', lawId: 'const-la-rioja', number: '176', title: '', text: `La necesidad de la reforma parcial o total de la constitución deberá ser declarada por ley con el voto de los dos tercios de los miembros de la Cámara de Diputados. Sancionada la ley y comunicada al Gobernador, este no podrá vetarla y deberá convocar a elecciones para elegir los Convencionales Constituyentes de acuerdo a lo establecido en esta Constitución y en la ley. La Convención no podrá incluir en la reforma otros puntos que los expresados en la Ley de Convocatoria, pero no está obligada a modificar, suprimir o complementar las disposiciones de la constitución cuando considere que no existe necesidad o conveniencia de la reforma. La Convención, en su primera sesión, fijará el término que estime necesario para desempeñar su cometido, el que no podrá exceder de un año desde la fecha de su constitución. La Convención sancionará, promulgará y publicará sus decisiones, que deben ser observadas como la expresión de la voluntad popular. ENMIENDA.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-177', lawId: 'const-la-rioja', number: '177', title: '', text: `La Cámara de Diputados de la Provincia podrá sancionar con el voto de lo dos tercios de sus miembros la enmienda de esta Constitución, que no podrá exceder de tres artículos, y sólo quedará incorporada al texto constitucional si fuere ratificada por consulta popular, que tendrá lugar en oportunidad de la primera elección general que se realice. Esta enmienda no podrá llevarse a cabo sino con intervalo de dos años. DISPOSICIONES TRANSITORIAS CLÁUSULA TRANSITORIA 1º.- Esta reforma entra en vigencia a partir de su sanción, es obligatoria para los poderes constituidos del Estado, disponiéndose lo necesario para que los funcionarios que lo integran juren esta Constitución. CLÁUSULA TRANSITORIA 2º.- Sancionada la Constitución los Convencionales Constituyentes prestarán juramento de cumplir sus disposiciones. El Gobernador, Vicegobernador, miembros del Tribunal Superior, Fiscal de Estado, Diputados, Intendentes y Viceintendentes municipales, lo harán ante la Convención Constituyente. Los jueces y miembros del Ministerio Público ante el Presidente del Tribunal Superior; y los demás funcionarios en la forma que se establezca en cada área. CLÁUSULA TRANSITORIA 3º.- El mandato del Gobernador y Vicegobernador, e Intendentes y Viceintendentes electos para el Período 2007-2011, deberá ser considerado como primer mandato. CLÁUSULA TRANSITORIA 4º.- Los diputados para la primera legislatura, Posterior a esta reforma constitucional, en el 2009, por única vez tratándose de una nueva integración de la Cámara prevista en esta Constitución, se nombrarán de la siguiente manera: 1.- En el año 2009: a) Se convocará a elecciones a las catorce (14) bancas cuyos mandatos finalizan en 2009, b) También se llamará para elegir a las trece (13) bancas necesarias para conformar la totalidad de la nueva composición, c) El número de integrantes se totaliza con las nueve (9) bancas cuyos mandatos caducan en el 2011. La convocatoria a elecciones se realizará de la siguiente manera: a) Mandato por cuatro (4) años: En el año 2009, se convocará por el Período 2009 -2013 a los departamentos: Capital para elegir siete (7) bancas; Coronel Felipe Varela, para elegir tres (3) bancas; Rosario Vera Peñaloza para la elección de tres (3) diputados; y Sanagasta, Castro Barros, Famatina, Vinchina, Gral. Juan Facundo Quiroga, elegirán un (1) diputado cada uno. b) Mandato por dos (2) años: También en el año 2009, se convocará para el Período 2009 - 2011, en la siguiente forma: de los últimos cinco (5) Departamentos: Sanagasta, Castro Barros, Famatina, Vinchina, Gral. Juan Facundo Quiroga que eligen un (1) diputado, en la primera sesión de la Cámara, del año 2009, deberá sortearse uno (1) cuyo mandato será por dos (2) años, a los Fines de lograr un número que permita la posterior renovación del Cuerpo. b.1.) Los departamentos Arauco, Chamical y Chilecito elegirán tres (3) diputados cada uno, con mandato por dos (2) años. b.2) La banca que corresponde a Capital, cuyo mandato finaliza el año 2011, se renovará, en esa elección, por un periodo de dos (2) años, lo cual permitirá unificar en el 2013 las ocho (8) bancas definitivas del distrito Capital. 2°) En el año 2011: A los fines de realizar el sistema de renovación constitucional según lo establecido en el`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-91º', lawId: 'const-la-rioja', number: '91º', title: '', text: `Artículo 91º, se convocará a elecciones para el Período 2011-2015, a los siguientes departamentos: Chilecito, cuatro (4) bancas; Arauco, tres (3) bancas; Chamical, tres (3) bancas; y General Lamadrid, General Belgrano, Ángel Vicente Peñaloza, General San Martín, General Ortiz de Ocampo, Independencia y San Blas de Los Sauces, el que resultó sorteado en el año 2009 que elegirán un (1) diputado. En cada una de estas convocatorias, y elecciones, deberá actuarse garantizando la participación de las minorías como ordena el`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-87º', lawId: 'const-la-rioja', number: '87º', title: '', text: `Artículo 87º, y el cumplimiento de lo establecido en el`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-81º', lawId: 'const-la-rioja', number: '81º', title: '', text: `Artículo 81º de la igualdad real de oportunidades. Al respecto, la Ley Electoral, impondrá como lo ordena el`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-87º-2', lawId: 'const-la-rioja', number: '87º', title: '', text: `Artículo 87º; que para la oficialización de las listas, la Justicia Electoral deberá respetar la igualdad de los géneros como requisito de validez para los Partidos Políticos.- CLÁUSULA TRANSITORIA 5º.- Los Concejos Deliberantes deberán integrarse para culminar su mandato en el año 2011, a cuyos fines, en el año 2009, por única vez, se convocará a elecciones por dos (2) años, por el tiempo que falte para completar el mandato del periodo 2007-2011, de acuerdo a lo establecido en el`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-la-rioja-art-169º', lawId: 'const-la-rioja', number: '169º', title: '', text: `CLÁUSULA TRANSITORIA 6º.- Hasta que se dicten las distintas leyes orgánicas Y leyes reglamentarias a que se hace referencia, u otras que se consideren necesarias, se aplicarán las normas de esta Constitución y supletoriamente las leyes en vigencia en todo aquello que sea compatible con el texto constitucional. Sancionada la Constitución, inmediatamente deberán llevarse a cabo los trámites pertinentes para integrar los órganos de selección y remoción de jueces y miembros del Ministerio Público para habilitar su funcionamiento. A los fines de la remoción de los jueces y miembros del Ministerio Público, el Jurado de Enjuiciamiento deberá aplicar, hasta tanto se dicte la pertinente ley, las normas constitucionales aplicables, y en todo lo no previsto, supletoriamente, la Ley N° 5.048 de Juicio Político con sus modificatorias. CLÁUSULA TRANSITORIA 7º.- A partir de la sanción de esta Constitución, Únicamente los pedidos de juicios políticos pendientes o en trámite, serán terminados por la Cámara de Diputados. Los que se pidieran deberán hacerlo siguiendo las previsiones de esta Constitución. CLÁUSULA TRANSITORIA 8º.- Que de acuerdo a lo establecido en la Ley Nº 8.183, se ha procedido a renumerar el texto de la Constitución Provincial. CLÁUSULA TRANSITORIA 9º.- Esta Convención Constituyente autoriza a la Cámara de Diputados para la publicación y posterior edición de esta Constitución, con las modificaciones introducidas. CLÁUSULA TRANSITORIA 10º.- Esta Convención ordena que toda la documentación recibida y generada durante su funcionamiento sea archivada y quede bajo la custodia de la Cámara de Diputados en la biblioteca de la misma. Firmantes FIRMANTES`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
];




